/**
 * Prayer mechanics content  –  wudu, the 14 step-by-step prayer postures, and
 * the after-prayer adhkar. Arabic dhikr stays hardcoded in the section
 * components; this file holds the narrative text only.
 *
 * The structure uses PartialLangMap (only `en` required, others optional). The
 * consuming components use the standard `entry[lang] ?? entry.en` fallback,
 * matching how every other content file in this repo handles incremental
 * translation. The 13 remaining languages are added per-turn (see TaskCreate
 * "Translate prayer-steps-content to 13 langs"  –  multi-turn marathon).
 */

type Lang = 'en' | 'ms' | 'tur' | 'urd' | 'ben' | 'fas' | 'zh' | 'yue' | 'ja' | 'ru' | 'es' | 'ko' | 'ta' | 'si';
type PartialLangMap = { en: string } & Partial<Record<Lang, string>>;

export type PrayerStepsContentKey = keyof typeof PRAYER_STEPS_CONTENT;

export const PRAYER_STEPS_CONTENT = {
  /* ── Page header ────────────────────────────────────────── */
  page_title: { en: `How to Pray (Salah)`, ms: `Cara Solat`, tur: `Namaz Nasıl Kılınır`, urd: `نماز کیسے پڑھیں`, ben: `কীভাবে নামাজ পড়বেন`, fas: `چگونگی خواندن نماز`, zh: `如何禮拜（撒拉特）`, yue: `點樣禮拜（撒拉特）`, ja: `礼拝（サラート）の仕方`, ru: `Как совершать намаз (Салят)`, es: `Cómo rezar (Salah)`, ko: `예배(살라) 드리는 방법`, ta: `எவ்வாறு தொழுவது (ஸலாத்)`, si: `සලාත් කරන ආකාරය` },
  page_subtitle: { en: `Salah is the second pillar of Islam: a direct link between the servant and his Lord, ordained by Allah Himself without any intermediary, during the greatest journey in human history.`, ms: `Solat ialah rukun kedua Islam: hubungan langsung antara hamba dengan Tuhannya, yang difardukan oleh Allah sendiri tanpa perantara, dalam perjalanan teragung dalam sejarah manusia.`, tur: `Namaz İslam'ın ikinci şartıdır: kul ile Rabbi arasındaki doğrudan bağ; Allah tarafından insanlık tarihinin en büyük yolculuğunda, hiçbir aracı olmaksızın bizzat farz kılınmıştır.`, urd: `نماز اسلام کا دوسرا رکن ہے: بندے اور اس کے رب کے درمیان براہِ راست رابطہ، جسے اللہ نے انسانی تاریخ کے سب سے عظیم سفر کے دوران بغیر کسی واسطے کے خود فرض کیا۔`, ben: `নামাজ ইসলামের দ্বিতীয় স্তম্ভ: বান্দা ও তার রবের মধ্যে সরাসরি সংযোগ, মানব ইতিহাসের সবচেয়ে মহান যাত্রার সময় কোনো মধ্যস্থতাকারী ছাড়াই স্বয়ং আল্লাহ কর্তৃক ফরজ করা।`, fas: `نماز رکن دوم اسلام است: پیوندی مستقیم میان بنده و پروردگارش که خداوند خود، در بزرگ‌ترین سفر تاریخ بشریت، بدون هیچ واسطه‌ای آن را فرض کرد.`, zh: `撒拉特乃伊斯蘭五功之第二：僕人與其主之間之直接聯繫，乃真主於人類歷史最偉大之旅程中親自定為主命，無任何中介。`, yue: `撒拉特乃伊斯蘭五功之第二：僕人與其主之間之直接聯繫，乃真主於人類歷史最偉大之旅程中親自定為主命，無任何中介。`, ja: `サラートはイスラムの第二の柱：人類史上最も偉大な旅において、いかなる仲介者もなくアッラー御自身が定められた、僕と主との直接の絆である。`, ru: `Салят – второй столп Ислама: прямая связь между рабом и его Господом, предписанная Самим Аллахом без какого-либо посредника во время величайшего путешествия в истории человечества.`, es: `La Salah es el segundo pilar del Islam: un vínculo directo entre el siervo y su Señor, ordenado por Allah mismo sin intermediario alguno, durante el viaje más grandioso de la historia humana.`, ko: `살라는 이슬람의 두 번째 기둥입니다: 인류 역사상 가장 위대한 여정 동안 어떤 중재자도 없이 알라께서 친히 정하신, 종과 그의 주님 사이의 직접적인 연결입니다.`, ta: `ஸலாத் இஸ்லாத்தின் இரண்டாவது தூண்: அடியானுக்கும் அவனது இறைவனுக்கும் இடையேயான நேரடி தொடர்பு, மனித வரலாற்றின் மிகப்பெரிய பயணத்தின் போது எந்த இடைத்தரகரும் இல்லாமல் அல்லாஹ்வே நேரடியாக கடமையாக்கியது.`, si: `සලාත් යනු ඉස්ලාම්හි දෙවන කුළුණයි: මනුෂ්‍ය ඉතිහාසයේ වඩාත්ම ශ්‍රේෂ්ඨ ගමන තුළදී කිසිදු මැදිහත්කරුවෙකු නොමැතිව අල්ලාහ් විසින්ම නියම කරන ලද, දාසයා සහ ඔහුගේ සමිඳු අතර සෘජු සම්බන්ධතාවයි.` },

  /* ── Wudu intro + steps ─────────────────────────────────── */
  wudu_h: { en: `Ritual Purification (Wudu) Before Prayer`, ms: `Penyucian Ritual (Wudu) Sebelum Solat`, tur: `Namazdan Önce Abdest (Wudu)`, urd: `نماز سے پہلے وضو`, ben: `নামাজের আগে অজু`, fas: `وضو پیش از نماز`, zh: `禮拜前之小淨（沃杜）`, yue: `禮拜前之小淨（沃杜）`, ja: `礼拝の前の小浄（ウドゥー）`, ru: `Ритуальное омовение (Вуду) перед намазом`, es: `Purificación ritual (Wudu) antes de la oración`, ko: `예배 전의 의례적 정화 (우두)`, ta: `தொழுகைக்கு முன் சடங்கு சுத்திகரிப்பு (வுளூ)`, si: `සලාතයට පෙර චාරිත්‍ර පවිත්‍රකරණය (වුළූඃ)` },
  wudu_intro: { en: `Wudu is obligatory before prayer. Jibril (as) first taught it to the Prophet ﷺ at the very beginning of revelation. Allah says: "O you who believe, when you rise to perform prayer, wash your faces and your hands to the elbows, wipe over your heads, and wash your feet to the ankles." (Qur'an 5:6). The Prophet ﷺ said: "No prayer is accepted without purity." (Muslim 224). For the full guide to wudu, ghusl and tayamum see the Taharah page.`, ms: `Wudu wajib sebelum solat. Jibril (as) yang pertama mengajarkannya kepada Nabi ﷺ pada permulaan wahyu. Allah berfirman: "Wahai orang yang beriman, apabila kamu hendak menunaikan solat, basuhlah mukamu dan tanganmu hingga ke siku, dan sapulah kepalamu, dan basuhlah kakimu hingga ke buku lali." (Al-Quran 5:6). Nabi ﷺ bersabda: "Tidak diterima solat tanpa kesucian." (Muslim 224). Untuk panduan penuh tentang wudu, ghusl dan tayamum, lihat halaman Taharah.`, tur: `Abdest namazdan önce farzdır. Cibril (as) onu ilk olarak Peygamber'e ﷺ vahyin başlangıcında öğretmiştir. Allah buyurur: "Ey iman edenler, namaza kalktığınızda yüzlerinizi ve dirseklerinize kadar ellerinizi yıkayın; başlarınızı meshedin ve topuklarınıza kadar ayaklarınızı yıkayın." (Kur'an 5:6). Peygamber ﷺ buyurdu: "Temizlik olmadan hiçbir namaz kabul olunmaz." (Müslim 224). Abdest, gusül ve teyemmüm hakkında tam rehber için Taharah sayfasına bakınız.`, urd: `نماز سے پہلے وضو فرض ہے۔ جبریل (ع) نے سب سے پہلے یہ نبی ﷺ کو وحی کے آغاز میں سکھایا۔ اللہ فرماتا ہے: "اے ایمان والو، جب تم نماز کے لیے کھڑے ہو تو اپنے چہرے اور ہاتھوں کو کہنیوں تک دھو لو، اور اپنے سروں کا مسح کرو، اور اپنے پاؤں کو ٹخنوں تک دھو لو۔" (قرآن ۵:۶)۔ نبی ﷺ نے فرمایا: "طہارت کے بغیر کوئی نماز قبول نہیں۔" (مسلم ۲۲۴)۔ وضو، غسل اور تیمم کی مکمل رہنمائی کے لیے طہارت کا صفحہ دیکھیں۔`, ben: `নামাজের আগে অজু ফরজ। জিবরিল (আ) সর্বপ্রথম এটি ওহির শুরুতে নবী ﷺ-কে শিখিয়েছেন। আল্লাহ বলেন: "হে ঈমানদারগণ, যখন তোমরা নামাজের জন্য দাঁড়াও, তখন তোমাদের মুখমণ্ডল ও কনুই পর্যন্ত হাত ধৌত কর, এবং তোমাদের মাথা মাসেহ কর, এবং গোড়ালি পর্যন্ত পা ধৌত কর।" (কুরআন ৫:৬)। নবী ﷺ বললেন: "পবিত্রতা ছাড়া কোনো নামাজ গ্রহণযোগ্য নয়।" (মুসলিম ২২৪)। অজু, গোসল ও তায়াম্মুমের পূর্ণ নির্দেশনার জন্য তাহারাহ পাতা দেখুন।`, fas: `وضو پیش از نماز واجب است. جبرئیل (ع) نخستین بار آن را در آغاز وحی به پیامبر ﷺ آموخت. خداوند می‌فرماید: "ای کسانی که ایمان آورده‌اید، چون به نماز برخیزید، چهره‌ها و دستان خود را تا آرنج بشویید و سرهای خود را مسح کنید و پاهای خود را تا قوزک بشویید." (قرآن ۵:۶). پیامبر ﷺ فرمود: "هیچ نمازی بدون طهارت پذیرفته نمی‌شود." (مسلم ۲۲۴). برای راهنمای کامل وضو، غسل و تیمم، صفحه طهارت را ببینید.`, zh: `禮拜前小淨乃主命。吉卜利里（願主賜他平安）於啟示之初最先教先知ﷺ此事。真主言：「信道之人啊，當你們起身禮拜時，當洗淨你們之臉與雙手至肘部，並抹頭，並洗腳至腳踝。」（古蘭5:6）。先知ﷺ言：「無潔淨則無拜功被接納。」（穆斯林224）。沃杜、大淨、土淨之完整指南，請參閱潔淨頁面。`, yue: `禮拜前小淨乃主命。吉卜利里（願主賜佢平安）於啟示之初最先教先知ﷺ此事。真主言：「信道之人啊，當你哋起身禮拜時，當洗淨你哋之臉與雙手至肘部，並抹頭，並洗腳至腳踝。」（古蘭5:6）。先知ﷺ言：「無潔淨則無拜功被接納。」（穆斯林224）。沃杜、大淨、土淨之完整指南，請參閱潔淨頁面。`, ja: `礼拝の前のウドゥーは義務である。ジブリール（に平安あれ）が啓示の始まりに最初に預言者ﷺに教えた。アッラーは仰せられる：「信仰する者よ、礼拝に立つとき、顔と肘までの両手を洗い、頭を撫で、両足を踝まで洗いなさい。」（クルアーン5:6）。預言者ﷺは仰せられた：「清浄なくして礼拝は受け入れられない。」（ムスリム224）。ウドゥー、グスル、タヤンマムの完全な手引きはタハーラのページを参照。`, ru: `Вуду обязательно перед намазом. Джибриль (мир ему) первым научил ему Пророка ﷺ в самом начале откровения. Аллах говорит: «О вы, кто уверовал, когда встаёте на молитву, омойте лица ваши и руки до локтей, протрите головы ваши и омойте ноги ваши до щиколоток.» (Коран 5:6). Пророк ﷺ сказал: «Не принимается ни одна молитва без чистоты.» (Муслим 224). Полное руководство по вуду, гуслю и таяммуму смотрите на странице Тахара.`, es: `El wudu es obligatorio antes de la oración. Yibril (as) se lo enseñó por primera vez al Profeta ﷺ al inicio mismo de la revelación. Allah dice: "Oh vosotros que creéis, cuando os dispongáis a orar, lavaos el rostro y las manos hasta los codos, pasaos las manos por la cabeza y lavaos los pies hasta los tobillos." (Corán 5:6). El Profeta ﷺ dijo: "No se acepta ninguna oración sin pureza." (Muslim 224). Para la guía completa de wudu, ghusl y tayamum, véase la página de Taharah.`, ko: `예배 전 우두는 의무입니다. 지브릴(평화가 그에게)께서 계시의 시작에 예언자 ﷺ께 처음 가르치셨습니다. 알라께서 말씀하시되: "오 믿는 자들이여, 예배를 위해 일어설 때 너희 얼굴과 팔꿈치까지의 손을 씻고 머리를 쓰다듬고 발목까지의 발을 씻으라." (꾸란 5:6). 예언자 ﷺ께서 말씀하셨다: "정결 없이는 어떤 예배도 받아들여지지 않는다." (무슬림 224). 우두, 구슬, 타얌뭄의 전체 안내는 타하라 페이지를 참조하십시오.`, ta: `தொழுகைக்கு முன் வுளூ கடமை. ஜிப்ரீல் (அலை) வஹியின் ஆரம்பத்திலேயே நபி ﷺ அவர்களுக்கு இதை முதலில் கற்றுக் கொடுத்தார். அல்லாஹ் கூறுகிறான்: "ஈமான் கொண்டவர்களே, நீங்கள் தொழுகைக்கு எழுந்தால், உங்கள் முகங்களையும் கைகளை முழங்கைகள் வரையும் கழுவுங்கள், உங்கள் தலைகளை மஸஹ் செய்யுங்கள், உங்கள் கால்களை கணுக்கால்கள் வரை கழுவுங்கள்." (குர்ஆன் 5:6). நபி ﷺ கூறினார்: "சுத்தம் இல்லாமல் எந்தத் தொழுகையும் ஏற்கப்படாது." (முஸ்லிம் 224). வுளூ, குஸ்ல், தயம்மம் பற்றிய முழு வழிகாட்டலுக்கு தஹாரா பக்கத்தைப் பார்க்கவும்.`, si: `සලාතයට පෙර වුළූඃ අනිවාර්යය. ජිබ්රීල් (අලෛ) එය ආරම්භයේදීම නබි ﷺ ට පළමුව ඉගැන්වීය. අල්ලාහ් මෙසේ පවසයි: "අහෝ විශ්වාසවන්තයිනි, ඔබ සලාතයට නැගිට්ටහොත් ඔබේ මුහුණු සහ වැළමිට් දක්වා දෑත් සෝදන්න, හිස මත අතගා, වළලුකර දක්වා පාද සෝදන්න." (කුර්ආන් 5:6). නබි ﷺ පැවසූහ: "පවිත්‍රත්වයකින් තොරව කිසිදු සලාතයක් පිළිගනු නොලැබේ." (මුස්ලිම් 224). වුළූඃ, ගුස්ල්, තයම්මුම් පිළිබඳ සම්පූර්ණ මාර්ගෝපදේශය සඳහා තහාරා පිටුව බලන්න.` },
  wudu_more: { en: `See the full Taharah page for wudu, ghusl, and tayamum`, ms: `Lihat halaman Taharah penuh untuk wudu, ghusl dan tayamum`, tur: `Abdest, gusül ve teyemmüm için tam Taharah sayfasını görün`, urd: `وضو، غسل اور تیمم کے لیے مکمل طہارت کا صفحہ دیکھیں`, ben: `অজু, গোসল ও তায়াম্মুমের জন্য সম্পূর্ণ তাহারাহ পাতা দেখুন`, fas: `برای وضو، غسل و تیمم صفحه کامل طهارت را ببینید`, zh: `查看完整潔淨頁面以了解沃杜、大淨與土淨`, yue: `查看完整潔淨頁面以了解沃杜、大淨與土淨`, ja: `ウドゥー、グスル、タヤンマムの全体はタハーラのページへ`, ru: `Полная страница Тахара по вуду, гуслю и таяммуму`, es: `Véase la página completa de Taharah para wudu, ghusl y tayamum`, ko: `우두, 구슬, 타얌뭄에 대한 전체 타하라 페이지 보기`, ta: `வுளூ, குஸ்ல், தயம்மம் முழுமைக்காக தஹாரா பக்கத்தைப் பார்க்கவும்`, si: `වුළූඃ, ගුස්ල්, තයම්මුම් සඳහා සම්පූර්ණ තහාරා පිටුව බලන්න` },

  wudu_s1_a: { en: `Intention (Niyyah)`, ms: `Niat`, tur: `Niyet`, urd: `نیت`, ben: `নিয়ত`, fas: `نیت`, zh: `舉意（尼亞）`, yue: `舉意（尼亞）`, ja: `意図（ニーヤ）`, ru: `Намерение (Ниййя)`, es: `Intención (Niyyah)`, ko: `의도 (니야)`, ta: `எண்ணம் (நிய்யத்)`, si: `අරමුණ (නිය්‍යා)` },
  wudu_s1_d: { en: `Make the intention in your heart to purify yourself for prayer. The Prophet ﷺ said: "Actions are by intentions." (Bukhari)`, ms: `Niatkan dalam hati untuk menyucikan diri bagi solat. Nabi ﷺ bersabda: "Sesungguhnya segala amal itu dengan niat." (Bukhari)`, tur: `Namaz için temizlenmek üzere kalbinden niyet et. Peygamber ﷺ buyurdu: "Ameller niyetlere göredir." (Buhârî)`, urd: `دل میں نماز کے لیے پاک ہونے کی نیت کرو۔ نبی ﷺ نے فرمایا: "اعمال کا دارومدار نیتوں پر ہے۔" (بخاری)`, ben: `নামাজের জন্য পবিত্র হওয়ার নিয়ত মনে মনে কর। নবী ﷺ বললেন: "নিশ্চয়ই কর্মসমূহ নিয়তের উপর নির্ভরশীল।" (বুখারি)`, fas: `در دل خود برای پاک شدن جهت نماز نیت کن. پیامبر ﷺ فرمود: "اعمال به نیت‌هاست." (بخاری)`, zh: `心中舉意，為禮拜而潔淨。先知ﷺ言：「諸事憑舉意。」（布哈里）`, yue: `心中舉意，為禮拜而潔淨。先知ﷺ言：「諸事憑舉意。」（布哈里）`, ja: `礼拝のために自身を清める意図を心に定める。預言者ﷺは仰せられた：「行ないは意図による。」（ブハーリー）`, ru: `Сделай намерение в сердце очиститься для намаза. Пророк ﷺ сказал: «Дела оцениваются по намерениям.» (Бухари)`, es: `Haz la intención en tu corazón de purificarte para la oración. El Profeta ﷺ dijo: "Las obras son según las intenciones." (Bujari)`, ko: `예배를 위해 자신을 정결케 하려는 의도를 마음에 두라. 예언자 ﷺ께서 말씀하시되: "행위는 의도에 따라 평가된다." (부카리)`, ta: `தொழுகைக்காக தன்னை சுத்தப்படுத்தும் எண்ணத்தை இதயத்தில் கொள்ளுங்கள். நபி ﷺ கூறினார்: "செயல்கள் எண்ணங்களைப் பொறுத்தே." (புகாரி)`, si: `සලාතය සඳහා ඔබව පවිත්‍ර කර ගැනීමේ අරමුණ සිතේ පිහිටුවන්න. නබි ﷺ පැවසූහ: "ක්‍රියා පදනම් වන්නේ අරමුණු මතය." (බුහාරි)` },
  wudu_s2_a: { en: `Say Bismillah`, ms: `Sebut Bismillah`, tur: `Besmele çek`, urd: `بسم اللہ کہو`, ben: `বিসমিল্লাহ বলুন`, fas: `بسم الله بگو`, zh: `念「奉真主之名」（比斯米拉）`, yue: `念「奉真主之名」（比斯米拉）`, ja: `「ビスミッラー（アッラーの御名において）」と唱える`, ru: `Скажи «Бисмиллях»`, es: `Di Bismillah`, ko: `비스밀라를 말하라`, ta: `பிஸ்மில்லாஹ் கூறுங்கள்`, si: `බිස්මිල්ලාහ් කියන්න` },
  wudu_s2_d: { en: `Begin with "Bismillah". The Prophet ﷺ said: "There is no wudu for one who does not mention the name of Allah over it." (Abu Dawud, Tirmidhi)`, ms: `Mulakan dengan "Bismillah". Nabi ﷺ bersabda: "Tidak ada wudu bagi orang yang tidak menyebut nama Allah ke atasnya." (Abu Daud, Tirmidhi)`, tur: `"Bismillah" diyerek başla. Peygamber ﷺ buyurdu: "Üzerine Allah'ın adını anmayanın abdesti yoktur." (Ebû Dâvûd, Tirmizî)`, urd: `"بسم اللہ" کے ساتھ شروع کرو۔ نبی ﷺ نے فرمایا: "اس کا وضو نہیں جس نے اس پر اللہ کا نام نہ لیا۔" (ابو داؤد، ترمذی)`, ben: `"বিসমিল্লাহ" দিয়ে শুরু করুন। নবী ﷺ বললেন: "যে ব্যক্তি অজুর শুরুতে আল্লাহর নাম উচ্চারণ করে না তার অজু নেই।" (আবু দাউদ, তিরমিযি)`, fas: `با "بسم الله" آغاز کن. پیامبر ﷺ فرمود: "وضویی نیست بر کسی که نام خدا را بر آن نبرد." (ابو داود، ترمذی)`, zh: `以「奉真主之名」開始。先知ﷺ言：「不念真主之名於小淨上者，其小淨無效。」（艾布·達伍德、提爾米茲）`, yue: `以「奉真主之名」開始。先知ﷺ言：「不念真主之名於小淨上者，其小淨無效。」（艾布·達伍德、提爾米茲）`, ja: `「ビスミッラー」で始める。預言者ﷺは仰せられた：「アッラーの御名を唱えない者にはウドゥーはない。」（アブー・ダーウード、ティルミズィー）`, ru: `Начни с «Бисмиллях». Пророк ﷺ сказал: «Нет вуду у того, кто не упомянул имя Аллаха над ним.» (Абу Дауд, Тирмизи)`, es: `Comienza con "Bismillah". El Profeta ﷺ dijo: "No hay wudu para quien no menciona el nombre de Allah sobre él." (Abu Dawud, Tirmidhi)`, ko: `"비스밀라"로 시작하라. 예언자 ﷺ께서 말씀하시되: "그 위에 알라의 이름을 부르지 않는 자에게는 우두가 없다." (아부 다우드, 티르미디)`, ta: `"பிஸ்மில்லாஹ்" உடன் ஆரம்பியுங்கள். நபி ﷺ கூறினார்: "அல்லாஹ்வின் பெயரை அதன் மீது சொல்லாதவருக்கு வுளூ இல்லை." (அபூ தாவூத், திர்மிதி)`, si: `"බිස්මිල්ලාහ්" කියමින් අරඹන්න. නබි ﷺ පැවසූහ: "ඊට අල්ලාහ්ගේ නාමය නොකියන තැනැත්තාට වුළූඃ නැත." (අබූ දාවූද්, තිර්මිදී)` },
  wudu_s3_a: { en: `Wash both hands × 3`, ms: `Basuh kedua tangan × 3`, tur: `Her iki eli yıka × 3`, urd: `دونوں ہاتھ × ۳ مرتبہ دھوئیں`, ben: `উভয় হাত × ৩ বার ধৌত করুন`, fas: `هر دو دست را ۳ بار بشویید`, zh: `洗雙手 × 3`, yue: `洗雙手 × 3`, ja: `両手を3回洗う`, ru: `Помой обе руки × 3`, es: `Lava ambas manos × 3`, ko: `양손을 3회 씻으라`, ta: `இரு கைகளையும் × 3 கழுவவும்`, si: `දෑත් × 3 සෝදන්න` },
  wudu_s3_d: { en: `Wash both hands up to and including the wrists three times, interlacing the fingers to ensure water reaches between them.`, ms: `Basuh kedua tangan hingga ke pergelangan tangan tiga kali, dengan menyelati jari-jari supaya air sampai ke celah-celahnya.`, tur: `İki eli bileklere kadar üç kez yıka; suyun parmak aralarına ulaşması için parmakları birbirine geçirerek hilalleme yap.`, urd: `دونوں ہاتھ کلائیوں تک تین بار دھوئیں، انگلیوں کے درمیان پانی پہنچانے کے لیے انہیں آپس میں خلال کریں۔`, ben: `উভয় হাত কব্জি পর্যন্ত তিনবার ধৌত করুন, আঙুলের ফাঁকে পানি পৌঁছানোর জন্য আঙুলগুলো পরস্পর প্রবেশ করিয়ে নিন।`, fas: `هر دو دست را تا مچ سه بار بشویید و انگشتان را در هم فرو ببرید تا آب میان آنها برسد.`, zh: `洗雙手連腕三次，將手指交叉以使水達於指間。`, yue: `洗雙手連手腕三次，將手指交叉以使水達於指間。`, ja: `両手を手首までを含めて3回洗い、指の間に水が届くよう指を組み合わせる。`, ru: `Помой обе руки до запястий три раза, переплетая пальцы, чтобы вода прошла между ними.`, es: `Lava ambas manos hasta las muñecas tres veces, entrelazando los dedos para que el agua llegue entre ellos.`, ko: `손목까지 양손을 세 번 씻고, 손가락을 깍지 끼어 그 사이에도 물이 닿게 하라.`, ta: `மணிக்கட்டுகள் வரை இரு கைகளையும் மூன்று முறை கழுவவும், நீர் விரல்களுக்கு இடையே போய்ச் சேருமாறு விரல்களை பின்னி கொள்ளவும்.`, si: `මැණික් කටුව දක්වා දෑත් තුන් වරක් සෝදන්න, ඇඟිලි අතරට ජලය ලැබෙන සේ ඇඟිලි එකිනෙකා සමඟ බැඳ ගන්න.` },
  wudu_s4_a: { en: `Rinse mouth × 3`, ms: `Berkumur-kumur × 3`, tur: `Ağzı çalkala × 3`, urd: `کلی کریں × ۳`, ben: `কুলি করুন × ৩`, fas: `دهان را ۳ بار بشویید`, zh: `漱口 × 3`, yue: `漱口 × 3`, ja: `口をすすぐ × 3`, ru: `Прополощи рот × 3`, es: `Enjuaga la boca × 3`, ko: `입을 헹구라 × 3`, ta: `வாயை × 3 கொப்பளிக்கவும்`, si: `මුඛය × 3 සෝදන්න` },
  wudu_s4_d: { en: `Take water into the mouth, swirl it thoroughly, and spit it out three times.`, ms: `Masukkan air ke dalam mulut, kumur-kumur dengan teliti, dan keluarkan tiga kali.`, tur: `Ağza su al, iyice çalkala ve üç kez at.`, urd: `پانی منہ میں لیں، اچھی طرح کلی کریں اور تین مرتبہ تھوک دیں۔`, ben: `মুখে পানি নিন, ভালোভাবে কুলি করুন ও তিনবার ফেলে দিন।`, fas: `آب در دهان بگیر، خوب بچرخان و سه بار بیرون بریز.`, zh: `將水含入口中，徹底漱動，吐出三次。`, yue: `將水含入口中，徹底漱動，吐出三次。`, ja: `水を口に含み、十分にすすいで吐き出す。これを3回繰り返す。`, ru: `Набери воду в рот, основательно прополощи и сплюнь три раза.`, es: `Lleva agua a la boca, enjuágala bien y escúpela tres veces.`, ko: `물을 입에 머금어 충분히 헹구고 뱉기를 세 번 반복하라.`, ta: `வாயில் நீரை எடுத்து நன்றாக சுழற்றி, மூன்று முறை துப்பவும்.`, si: `මුඛය තුළට ජලය ගෙන, හොඳින් කරකවා, තුන් වරක් කෙළ ගසන්න.` },
  wudu_s5_a: { en: `Clean nose × 3`, ms: `Bersihkan hidung × 3`, tur: `Burnu temizle × 3`, urd: `ناک صاف کریں × ۳`, ben: `নাক পরিষ্কার করুন × ৩`, fas: `بینی را ۳ بار پاک کنید`, zh: `潔淨鼻孔 × 3`, yue: `潔淨鼻孔 × 3`, ja: `鼻を清める × 3`, ru: `Очисти нос × 3`, es: `Limpia la nariz × 3`, ko: `코를 정결케 하라 × 3`, ta: `மூக்கை × 3 சுத்தம் செய்யவும்`, si: `නාසය × 3 පවිත්‍ර කරන්න` },
  wudu_s5_d: { en: `Sniff water into the nostrils and blow it out three times, using the left hand to blow.`, ms: `Hisap air ke dalam lubang hidung dan hembus keluar tiga kali, menggunakan tangan kiri untuk menghembus.`, tur: `Burnu su ile çek ve üç kez sümkür; sümkürmek için sol eli kullan.`, urd: `پانی ناک میں چڑھائیں اور تین بار جھاڑ دیں، جھاڑنے کے لیے بایاں ہاتھ استعمال کریں۔`, ben: `নাকের ছিদ্রে পানি টেনে তিনবার ঝেড়ে ফেলুন; ঝাড়ার জন্য বাম হাত ব্যবহার করুন।`, fas: `آب را در بینی بکش و سه بار بیرون بفرست، برای بیرون فرستادن از دست چپ استفاده کن.`, zh: `將水吸入鼻孔，以左手擤出三次。`, yue: `將水吸入鼻孔，以左手擤出三次。`, ja: `鼻孔に水を吸い上げ、左手で吹き出す。これを3回繰り返す。`, ru: `Втяни воду в ноздри и высморкай три раза, для высмаркивания используя левую руку.`, es: `Aspira agua por la nariz y suénala tres veces, usando la mano izquierda para sonarte.`, ko: `콧구멍에 물을 들이마셔 세 번 풀어내라. 풀어낼 때는 왼손을 사용하라.`, ta: `மூக்கு துளைகளில் நீரை இழுத்து, இடது கையால் மூன்று முறை வெளியேற்றவும்.`, si: `නාසය තුළට ජලය ඇද ගෙන, වම් අතින් තුන් වරක් පිට කරන්න.` },
  wudu_s6_a: { en: `Wash face × 3`, ms: `Basuh muka × 3`, tur: `Yüzü yıka × 3`, urd: `چہرہ دھوئیں × ۳`, ben: `মুখমণ্ডল ধৌত করুন × ৩`, fas: `چهره را ۳ بار بشویید`, zh: `洗臉 × 3`, yue: `洗臉 × 3`, ja: `顔を洗う × 3`, ru: `Помой лицо × 3`, es: `Lava el rostro × 3`, ko: `얼굴을 씻으라 × 3`, ta: `முகத்தை × 3 கழுவவும்`, si: `මුහුණ × 3 සෝදන්න` },
  wudu_s6_d: { en: `Wash the entire face from the hairline to the chin and from ear to ear, three times.`, ms: `Basuh seluruh muka dari batas rambut hingga ke dagu dan dari telinga ke telinga, sebanyak tiga kali.`, tur: `Yüzün tamamını saç çizgisinden çeneye, kulaktan kulağa üç kez yıka.`, urd: `پورا چہرہ بالوں کی حد سے ٹھوڑی تک اور ایک کان سے دوسرے کان تک تین بار دھوئیں۔`, ben: `কপালের চুলের সীমা থেকে চিবুক পর্যন্ত এবং এক কান থেকে অন্য কান পর্যন্ত পুরো মুখ তিনবার ধৌত করুন।`, fas: `تمام چهره را از رستنگاه مو تا چانه و از یک گوش تا گوش دیگر سه بار بشویید.`, zh: `自髮際至下頦、自一耳至另一耳，將整個面部洗三次。`, yue: `自髮際至下頦、自一耳至另一耳，將整個面部洗三次。`, ja: `生え際から顎まで、耳から耳までの顔全体を3回洗う。`, ru: `Помой всё лицо от линии волос до подбородка и от уха до уха три раза.`, es: `Lava todo el rostro desde el nacimiento del cabello hasta el mentón y de oreja a oreja, tres veces.`, ko: `머리카락 경계에서 턱까지, 귀에서 귀까지 얼굴 전체를 세 번 씻으라.`, ta: `தலைமுடி வரம்பிலிருந்து கீழ்த்தாடை வரை, காதிலிருந்து காது வரை முழு முகத்தையும் மூன்று முறை கழுவவும்.`, si: `කෙස් රේඛාවේ සිට නිකට දක්වා, කනක සිට කන දක්වා මුළු මුහුණ තුන් වරක් සෝදන්න.` },
  wudu_s7_a: { en: `Wash arms × 3`, ms: `Basuh kedua lengan × 3`, tur: `Kolları yıka × 3`, urd: `بازو دھوئیں × ۳`, ben: `উভয় হাত (বাহু) ধৌত করুন × ৩`, fas: `دست‌ها را ۳ بار بشویید`, zh: `洗雙臂 × 3`, yue: `洗雙臂 × 3`, ja: `両腕を洗う × 3`, ru: `Помой руки до локтей × 3`, es: `Lava los brazos × 3`, ko: `양팔을 씻으라 × 3`, ta: `கைகளை × 3 கழுவவும்`, si: `දෑත් × 3 සෝදන්න (වැළමිට් දක්වා)` },
  wudu_s7_d: { en: `Wash the right arm from fingertips to and including the elbow three times, then the left arm the same way.`, ms: `Basuh lengan kanan dari hujung jari hingga ke siku tiga kali, kemudian lengan kiri dengan cara yang sama.`, tur: `Sağ kolu parmak uçlarından dirseğe kadar üç kez yıka, sonra sol kolu aynı şekilde.`, urd: `دایاں بازو انگلیوں کے سرے سے کہنی تک تین بار دھوئیں، پھر بایاں بازو اسی طرح۔`, ben: `ডান হাত আঙুলের ডগা থেকে কনুই পর্যন্ত তিনবার ধৌত করুন, এরপর বাম হাত একইভাবে।`, fas: `دست راست را از سر انگشتان تا آرنج سه بار بشویید، سپس دست چپ را به همان شکل.`, zh: `將右臂自指尖洗至連肘部三次，再以同樣方式洗左臂。`, yue: `將右臂自指尖洗至連肘部三次，再以同樣方式洗左臂。`, ja: `右腕を指先から肘までを含めて3回洗い、次に左腕も同様に行う。`, ru: `Помой правую руку от кончиков пальцев до локтя включительно три раза, затем левую руку так же.`, es: `Lava el brazo derecho desde las puntas de los dedos hasta incluir el codo tres veces, luego el izquierdo del mismo modo.`, ko: `오른팔을 손끝부터 팔꿈치까지 포함하여 세 번 씻고, 그다음 왼팔을 같은 방식으로 씻으라.`, ta: `வலது கையை விரல் நுனிகளில் இருந்து முழங்கை வரை மூன்று முறை கழுவவும், பின் இடது கையை அவ்வாறே.`, si: `දකුණු දෑත අත් කෙළවරේ සිට වැළමිට් දක්වා තුන් වරක් සෝදන්න, ඉන් පසු වම් දෑත එලෙසම.` },
  wudu_s8_a: { en: `Wipe the head once`, ms: `Sapu kepala sekali`, tur: `Başı bir kez meshet`, urd: `سر کا ایک بار مسح`, ben: `মাথা একবার মাসেহ করুন`, fas: `سر را یک بار مسح کن`, zh: `抹頭一次`, yue: `抹頭一次`, ja: `頭を1回撫でる（メシ）`, ru: `Протри голову один раз`, es: `Pasa las manos por la cabeza una vez`, ko: `머리를 한 번 쓰다듬으라`, ta: `தலையை ஒரு முறை மஸஹ் செய்யவும்`, si: `හිස එක් වරක් අතගා මෙසේ කරන්න` },
  wudu_s8_d: { en: `With wet hands, wipe the head from front to back and bring the hands back to the front (once). Then wipe inside and outside the ears with the index fingers and thumbs.`, ms: `Dengan tangan basah, sapu kepala dari hadapan ke belakang dan bawa kembali ke hadapan (sekali). Kemudian sapu bahagian dalam dan luar telinga dengan jari telunjuk dan ibu jari.`, tur: `Islak elle başı önden arkaya meshet ve elleri tekrar öne getir (bir kez). Sonra şehadet parmakları ve baş parmaklarla kulakların içini ve dışını meshet.`, urd: `گیلے ہاتھوں سے سر کا اگلے سے پچھلے حصے تک مسح کریں اور ہاتھوں کو واپس آگے لائیں (ایک بار)۔ پھر شہادت کی انگلیوں اور انگوٹھوں سے کانوں کے اندر اور باہر مسح کریں۔`, ben: `ভেজা হাত দিয়ে মাথার সামনে থেকে পেছনে এবং পেছন থেকে আবার সামনে এনে একবার মাসেহ করুন। এরপর তর্জনী ও বৃদ্ধাঙ্গুলি দিয়ে কানের ভেতর ও বাইরে মাসেহ করুন।`, fas: `با دست‌های مرطوب، سر را از جلو به عقب مسح کن و دست‌ها را به جلو بازگردان (یک بار). سپس با انگشتان اشاره و شست داخل و بیرون گوش‌ها را مسح کن.`, zh: `以濕手自前向後抹頭，再將手回至前方（一次）。然後以食指與拇指抹耳之內外。`, yue: `以濕手自前向後抹頭，再將手回至前方（一次）。然後以食指與拇指抹耳之內外。`, ja: `濡れた手で頭を前から後ろへ撫で、また前へ戻す（1回）。それから人差し指と親指で耳の内側と外側を拭く。`, ru: `Влажными руками протри голову от лба к затылку и обратно ко лбу (один раз). Затем указательными и большими пальцами протри уши внутри и снаружи.`, es: `Con las manos húmedas, pasa por la cabeza de adelante hacia atrás y de vuelta hacia adelante (una vez). Luego pasa por el interior y el exterior de las orejas con los dedos índices y pulgares.`, ko: `젖은 손으로 머리를 앞에서 뒤로 쓸어내고 다시 앞으로 가져오기를 한 번 한다. 그런 다음 검지와 엄지로 귀 안팎을 닦는다.`, ta: `ஈரமான கைகளால் தலையை முன்னிருந்து பின்னோக்கி தடவி மீண்டும் முன்னோக்கி கொண்டுவாருங்கள் (ஒரு முறை). பின் ஆட்காட்டி விரல்கள் மற்றும் கட்டை விரல்களால் காதுகளின் உள்ளும் வெளியும் தடவவும்.`, si: `තෙත් අත්වලින් හිස ඉදිරියේ සිට පිටුපසට අතගා, නැවත ඉදිරියට ගෙන එන්න (එක් වරක්). ඉන් පසු කනේ ඇතුළ සහ පිට අත් මැද ඇඟිලි සහ මාපට ඇඟිලිවලින් අතගා මෙසේ කරන්න.` },
  wudu_s9_a: { en: `Wash feet × 3`, ms: `Basuh kedua kaki × 3`, tur: `Ayakları yıka × 3`, urd: `پاؤں دھوئیں × ۳`, ben: `পা ধৌত করুন × ৩`, fas: `پاها را ۳ بار بشویید`, zh: `洗雙足 × 3`, yue: `洗雙足 × 3`, ja: `両足を洗う × 3`, ru: `Помой ноги × 3`, es: `Lava los pies × 3`, ko: `발을 씻으라 × 3`, ta: `கால்களை × 3 கழுவவும்`, si: `පාද × 3 සෝදන්න` },
  wudu_s9_d: { en: `Wash the right foot up to and including the ankle three times, ensuring water reaches between the toes. Then the left foot. The Prophet ﷺ was strict that no part was left dry.`, ms: `Basuh kaki kanan hingga ke buku lali tiga kali, pastikan air sampai ke celah-celah jari kaki. Kemudian kaki kiri. Nabi ﷺ tegas bahawa tiada bahagian yang tertinggal kering.`, tur: `Sağ ayağı topuğa kadar üç kez yıka; suyun ayak parmaklarının arasına ulaştığından emin ol. Sonra sol ayağı. Peygamber ﷺ hiçbir yerin kuru kalmaması konusunda kesin davranırdı.`, urd: `دایاں پاؤں ٹخنے تک تین بار دھوئیں، یقینی بنائیں کہ پانی انگلیوں کے درمیان پہنچے۔ پھر بایاں پاؤں۔ نبی ﷺ سختی فرماتے تھے کہ کوئی حصہ خشک نہ رہے۔`, ben: `ডান পা গোড়ালি পর্যন্ত তিনবার ধৌত করুন, পায়ের আঙুলের ফাঁকে পানি পৌঁছানো নিশ্চিত করুন। এরপর বাম পা। নবী ﷺ কঠোর ছিলেন যে কোনো অংশ যেন শুকনো না থাকে।`, fas: `پای راست را تا قوزک سه بار بشویید و مطمئن شوید آب میان انگشتان می‌رسد. سپس پای چپ. پیامبر ﷺ سخت‌گیر بود که هیچ بخشی خشک نماند.`, zh: `將右腳洗連腳踝三次，務使水達於趾間。然後洗左腳。先知ﷺ嚴囑勿留乾處。`, yue: `將右腳洗連腳踝三次，務使水達於趾間。然後洗左腳。先知ﷺ嚴囑勿留乾處。`, ja: `右足を踝までを含めて3回洗い、足の指の間に水が届くようにする。次に左足。預言者ﷺは乾いた部分が残らないよう厳格であった。`, ru: `Помой правую ногу до щиколотки включительно три раза, обеспечивая попадание воды между пальцами. Затем левую ногу. Пророк ﷺ был строг, чтобы ни одна часть не оставалась сухой.`, es: `Lava el pie derecho hasta incluir el tobillo tres veces, asegurándote de que el agua llegue entre los dedos. Luego el pie izquierdo. El Profeta ﷺ era estricto en que ninguna parte quedara seca.`, ko: `오른발을 발목까지 포함하여 세 번 씻고, 발가락 사이에도 물이 닿도록 하라. 그다음 왼발. 예언자 ﷺ께서는 마른 부분이 남지 않도록 엄격하셨다.`, ta: `வலது காலை கணுக்கால் வரை மூன்று முறை கழுவவும், கால் விரல்களுக்கு இடையே நீர் சேருவதை உறுதி செய்யவும். பின் இடது கால். எந்த பகுதியும் காய்ந்து இருக்காதவாறு நபி ﷺ கண்டிப்பாக இருந்தார்.`, si: `දකුණු පාදය වළලුකර දක්වා තුන් වරක් සෝදන්න, ඇඟිලි අතරට ජලය ලැබෙන සේ සහතික කරන්න. ඉන් පසු වම් පාදය. කිසිදු කොටසක් වියළිව නොසිටිය යුතු බවට නබි ﷺ දැඩිව සිටියහ.` },

  wudu_dua_h: { en: `Du'a after Wudu (Muslim 234)`, ms: `Doa selepas Wudu (Muslim 234)`, tur: `Abdestten Sonra Dua (Müslim 234)`, urd: `وضو کے بعد دعا (مسلم ۲۳۴)`, ben: `অজুর পরের দোয়া (মুসলিম ২৩৪)`, fas: `دعای پس از وضو (مسلم ۲۳۴)`, zh: `小淨後之祈禱（穆斯林234）`, yue: `小淨後之祈禱（穆斯林234）`, ja: `ウドゥーの後の祈り（ムスリム234）`, ru: `Дуа после вуду (Муслим 234)`, es: `Du'a después del wudu (Muslim 234)`, ko: `우두 후의 두아 (무슬림 234)`, ta: `வுளூவுக்குப் பின் துஆ (முஸ்லிம் 234)`, si: `වුළූඃවලින් පසු දුආව (මුස්ලිම් 234)` },
  wudu_dua_translit: { en: `Ashhadu alla ilaha illallahu wahdahu la sharika lahu wa ashhadu anna Muhammadan 'abduhu wa rasuluh. Allahumma aj'alni minat-tawwabina waj'alni minal-mutatahhirin.` },
  wudu_dua_meaning: { en: `I bear witness that there is no god but Allah alone, He has no partner, and I bear witness that Muhammad is His servant and messenger. O Allah, make me of those who repent and make me of those who purify themselves.`, ms: `Aku bersaksi bahawa tiada tuhan selain Allah yang Esa, tiada sekutu bagi-Nya, dan aku bersaksi bahawa Muhammad adalah hamba dan pesuruh-Nya. Ya Allah, jadikanlah aku dari kalangan orang yang bertaubat, dan jadikanlah aku dari kalangan orang yang menyucikan diri.`, tur: `Allah'tan başka ilâh olmadığına, O'nun bir ve ortağı bulunmadığına şahadet ederim; ve Muhammed'in O'nun kulu ve resulü olduğuna şahadet ederim. Allah'ım, beni tövbe edenlerden ve temizlenenlerden eyle.`, urd: `میں گواہی دیتا ہوں کہ اللہ کے سوا کوئی معبود نہیں، وہ اکیلا ہے اس کا کوئی شریک نہیں، اور میں گواہی دیتا ہوں کہ محمد اس کے بندے اور رسول ہیں۔ اے اللہ، مجھے توبہ کرنے والوں میں سے بنا اور پاک رہنے والوں میں سے بنا۔`, ben: `আমি সাক্ষ্য দিচ্ছি যে আল্লাহ ছাড়া কোনো উপাস্য নেই, তিনি একক, তাঁর কোনো শরিক নেই; এবং আমি সাক্ষ্য দিচ্ছি যে মুহাম্মদ তাঁর বান্দা ও রাসূল। হে আল্লাহ, আমাকে তওবাকারীদের অন্তর্ভুক্ত করুন এবং পবিত্রতা অবলম্বনকারীদের অন্তর্ভুক্ত করুন।`, fas: `گواهی می‌دهم که هیچ معبودی جز خدا نیست، یگانه است و شریکی ندارد، و گواهی می‌دهم که محمد بنده و فرستاده اوست. خداوندا، مرا از توبه‌کنندگان قرار ده و از پاک‌شوندگان قرار ده.`, zh: `我作證：除真主外絕無應受崇拜者，祂獨一無偶；我作證：穆罕默德是祂的僕人與使者。真主啊，使我成為悔過者，使我成為自潔者。`, yue: `我作證：除真主外絕無應受崇拜者，祂獨一無偶；我作證：穆罕默德係祂嘅僕人與使者。真主啊，使我成為悔過者，使我成為自潔者。`, ja: `アッラーのほかに神はなく、唯一にして並ぶ者なきことを証言します。そしてムハンマドは彼のしもべであり使徒であることを証言します。アッラーよ、私を悔い改める者となし、自らを清める者となし給え。`, ru: `Свидетельствую, что нет божества, кроме Аллаха единого, у Которого нет сотоварища, и свидетельствую, что Мухаммад – Его раб и Посланник. О Аллах, сделай меня из числа кающихся и сделай меня из числа очищающихся.`, es: `Atestiguo que no hay dios sino Allah, Él es Uno y sin asociado, y atestiguo que Muhammad es Su siervo y mensajero. Oh Allah, hazme de los que se arrepienten y de los que se purifican.`, ko: `알라 외에 신이 없고 그분은 유일하시며 동반자가 없으심을 증언합니다. 또한 무함마드께서 그분의 종이며 사자이심을 증언합니다. 오 알라여, 저를 회개하는 자들 중에, 그리고 자신을 정결케 하는 자들 중에 두소서.`, ta: `அல்லாஹ்வைத் தவிர வணக்கத்திற்குரியவன் இல்லை, அவன் ஒருவனே, அவனுக்கு கூட்டாளி இல்லை, மற்றும் முஹம்மது அவன் அடியானும் தூதரும் என நான் சாட்சியம் கூறுகிறேன். அல்லாஹ்வே, என்னை தவ்பா செய்வோரில் ஆக்குவாயாக, என்னை சுத்தம் செய்து கொள்வோரில் ஆக்குவாயாக.`, si: `අල්ලාහ් හැර වෙනත් දෙවියෙකු නැති බවට මම සාක්ෂි දරමි, ඔහු එක්කෙනෙක්, ඔහුට හවුල්කරුවෙක් නැත; සහ මුහම්මද් ඔහුගේ දාසයා සහ දූතයාණන් බවට මම සාක්ෂි දරමි. අල්ලාහ්, මාව තව්බා කරන්නන්ගෙන් කෙනෙකු ලෙස පත් කරන්න, මාව පවිත්‍ර කරගන්නන්ගෙන් කෙනෙකු ලෙස පත් කරන්න.` },
  wudu_dua_note: { en: `The Prophet ﷺ said: "Whoever performs wudu well, then raises his gaze to the sky and says this: the eight gates of Paradise are opened for him to enter from whichever he wishes."`, ms: `Nabi ﷺ bersabda: "Sesiapa yang berwudu dengan baik, kemudian mengangkat pandangannya ke langit dan mengucapkan ini: dibukakan baginya lapan pintu Syurga untuk masuk dari mana sahaja yang dia mahu."`, tur: `Peygamber ﷺ buyurdu: "Kim güzelce abdest alır, sonra gözünü göğe kaldırır ve şunu söylerse: ona cennetin sekiz kapısı açılır, dilediğinden girer."`, urd: `نبی ﷺ نے فرمایا: "جو شخص اچھی طرح وضو کرے، پھر اپنی نگاہ آسمان کی طرف اٹھائے اور یہ کہے: اس کے لیے جنت کے آٹھ دروازے کھول دیے جاتے ہیں، جس سے چاہے داخل ہو۔"`, ben: `নবী ﷺ বললেন: "যে ব্যক্তি ভালোভাবে অজু করে, এরপর আকাশের দিকে দৃষ্টি তোলে এবং এই দোয়া পাঠ করে: তার জন্য জান্নাতের আটটি দরজা খুলে দেওয়া হয়, সে যে কোনোটি দিয়ে প্রবেশ করতে পারে।"`, fas: `پیامبر ﷺ فرمود: "هرکس وضو را نیکو بگیرد، سپس نگاه خود را به آسمان بلند کند و این را بگوید: هشت در بهشت برایش گشوده می‌شود، از هر یک که خواست داخل می‌شود."`, zh: `先知ﷺ言：「凡善作小淨者，舉目望天而誦此辭，則為其開樂園之八門，任其由所欲之門而入。」`, yue: `先知ﷺ言：「凡善作小淨者，舉目望天而誦此辭，則為其開樂園之八門，任其由所欲之門而入。」`, ja: `預言者ﷺは仰せられた：「ウドゥーを正しく行い、天を仰いでこれを唱える者には、楽園の八つの門が開かれ、望むどの門からでも入ることができる。」`, ru: `Пророк ﷺ сказал: «Кто хорошо совершит вуду, затем поднимет взор к небу и скажет это – для него открываются восемь врат Рая, чтобы он вошёл через любые из них.»`, es: `El Profeta ﷺ dijo: "Quien realice bien el wudu, luego eleve la mirada al cielo y diga esto: se le abren las ocho puertas del Paraíso para que entre por la que desee."`, ko: `예언자 ﷺ께서 말씀하시되: "우두를 잘 행한 뒤 하늘을 향해 시선을 들어 이것을 말하는 자에게는 천국의 여덟 문이 열려, 그가 원하는 어느 문으로든 들어갈 수 있다."`, ta: `நபி ﷺ கூறினார்: "வுளூவை சிறப்பாக செய்து, பின் வானத்தை நோக்கி பார்வையை உயர்த்தி இதை ஓதுபவருக்கு, சொர்க்கத்தின் எட்டு வாயில்கள் திறக்கப்படுகின்றன, அவர் விரும்பும் எந்த வாயிலின் வழியாகவும் நுழையலாம்."`, si: `නබි ﷺ පැවසූහ: "කවරෙකු හොඳින් වුළූඃ ඉටු කර, අහස දෙසට බැලුම් හෙළා මෙය කියන්නේද, ඔහුට ස්වර්ගයේ දොරටු අටක් විවෘත වේ; කැමති දොරටුවකින් ඔහු ඇතුළු විය හැකිය."` },

  /* ── The 14 prayer steps ────────────────────────────────── */
  steps_h: { en: `The Steps of Prayer`, ms: `Langkah-langkah Solat`, tur: `Namazın Aşamaları`, urd: `نماز کے مراحل`, ben: `নামাজের ধাপসমূহ`, fas: `مراحل نماز`, zh: `禮拜之步驟`, yue: `禮拜之步驟`, ja: `礼拝の手順`, ru: `Этапы намаза`, es: `Los pasos de la oración`, ko: `예배의 단계`, ta: `தொழுகையின் படிநிலைகள்`, si: `සලාතයේ පියවර` },
  steps_intro: { en: `Each prayer follows the same fourteen-step pattern. The Arabic dhikr below is hardcoded as the Prophet ﷺ taught it; only the narrative around each step translates.`, ms: `Setiap solat mengikuti pola empat belas langkah yang sama. Zikir Arab di bawah dikekalkan sebagaimana yang diajarkan oleh Nabi ﷺ; hanya naratif di sekeliling setiap langkah yang diterjemahkan.`, tur: `Her namaz aynı on dört aşamalı düzeni takip eder. Aşağıdaki Arapça zikirler Peygamber'in ﷺ öğrettiği gibi sabit bırakılmıştır; sadece her aşamanın etrafındaki anlatım çevrilir.`, urd: `ہر نماز اسی چودہ مرحلوں کے انداز پر چلتی ہے۔ نیچے دیے گئے عربی اذکار اسی طرح ثابت رکھے گئے ہیں جیسے نبی ﷺ نے سکھائے؛ صرف ہر مرحلے کے گرد کا بیان ترجمہ ہوتا ہے۔`, ben: `প্রতিটি নামাজ একই চৌদ্দ-ধাপ বিন্যাস অনুসরণ করে। নিচের আরবি যিকরসমূহ যেমন নবী ﷺ শিখিয়েছেন তেমনই অপরিবর্তিত রাখা হয়েছে; কেবল প্রতিটি ধাপের চারপাশের বিবরণই অনুবাদ করা হয়।`, fas: `هر نماز از همان الگوی چهارده‌مرحله‌ای پیروی می‌کند. اذکار عربی زیر همان‌گونه که پیامبر ﷺ آموخت ثابت مانده‌اند؛ تنها روایت پیرامون هر مرحله ترجمه می‌شود.`, zh: `每次禮拜皆遵循同一之十四步順序。下方阿拉伯文之贊念詞乃先知ﷺ所教，原樣保留；唯各步周圍之敘述被翻譯。`, yue: `每次禮拜皆遵循同一之十四步順序。下方阿拉伯文之贊念詞乃先知ﷺ所教，原樣保留；唯各步周圍之敘述被翻譯。`, ja: `すべての礼拝は同じ十四段階の手順をたどる。以下のアラビア語のズィクルは預言者ﷺが教えた通り変更しない。各段階を取り巻く解説のみを翻訳する。`, ru: `Каждый намаз следует одному и тому же четырнадцатишаговому порядку. Арабские зикры ниже сохранены такими, как им научил Пророк ﷺ; переводится только повествование вокруг каждого шага.`, es: `Cada oración sigue el mismo patrón de catorce pasos. Los dhikr en árabe que aparecen abajo se conservan tal como los enseñó el Profeta ﷺ; sólo se traduce la narración alrededor de cada paso.`, ko: `모든 예배는 동일한 열네 단계의 순서를 따릅니다. 아래의 아랍어 지크르는 예언자 ﷺ께서 가르치신 그대로 고정되어 있으며, 각 단계 주변의 설명만 번역됩니다.`, ta: `ஒவ்வொரு தொழுகையும் ஒரே பதினான்கு படிநிலை அமைப்பைப் பின்பற்றுகிறது. கீழே உள்ள அரபி திக்ர் நபி ﷺ கற்பித்தபடியே மாறாமல் வைக்கப்படுகிறது; ஒவ்வொரு படியைச் சுற்றியுள்ள விளக்கம் மட்டுமே மொழிபெயர்க்கப்படுகிறது.`, si: `සෑම සලාතයක්ම එකම පියවර හතරදහයේ රටාව අනුගමනය කරයි. පහත අරාබි දික්ර් නබි ﷺ ඉගැන්වූ පරිදිම තබා ඇත; සෑම පියවරක් වටා ඇති විස්තරය පමණක් පරිවර්තනය වේ.` },

  step1_t: { en: `Facing the Qibla`, ms: `Menghadap Kiblat`, tur: `Kıbleye Yönelmek`, urd: `قبلہ رخ ہونا`, ben: `কিবলামুখী হওয়া`, fas: `رو به قبله ایستادن`, zh: `面向朝向（基卜萊）`, yue: `面向朝向（基卜萊）`, ja: `キブラ（カアバの方角）に向かう`, ru: `Поворот к кибле`, es: `Orientarse hacia la Qibla`, ko: `끼블라(까바)를 향함`, ta: `கிப்லாவை நோக்குதல்`, si: `කිබ්ලාවට මුහුණලීම` },
  step1_d: { en: `Stand facing the Qibla, the direction of the Ka'bah in Makkah. This is obligatory; deliberately facing the wrong direction invalidates the prayer. Stand upright, feet roughly shoulder-width apart, with full presence of heart (khushu'). You are about to stand before Allah, just as the Prophet ﷺ stood before Him during the Night Journey.`, ms: `Berdirilah menghadap Kiblat, arah Kaabah di Makkah. Ini adalah wajib; sengaja menghadap arah yang salah membatalkan solat. Berdiri tegak, kaki lebih kurang sama dengan lebar bahu, dengan sepenuh kehadiran hati (khusyuk). Anda akan berdiri di hadapan Allah, sebagaimana Nabi ﷺ berdiri di hadapan-Nya pada malam Isra'.`, tur: `Mekke'deki Kâbe'nin yönü olan kıbleye dönerek ayağa kalk. Bu farzdır; kasten yanlış yöne dönmek namazı bozar. Dimdik dur, ayaklar yaklaşık omuz genişliğinde açık, tam bir kalp huzuruyla (huşû). Mîrac gecesinde Peygamber'in ﷺ O'nun huzurunda durduğu gibi, sen de şimdi Allah'ın huzurunda duracaksın.`, urd: `قبلہ کی طرف منہ کر کے کھڑے ہوں، یعنی مکہ میں کعبہ کی سمت۔ یہ فرض ہے؛ جان بوجھ کر غلط سمت ہونا نماز کو باطل کر دیتا ہے۔ سیدھے کھڑے ہوں، پاؤں تقریباً کندھوں کے برابر، پورے دل کی حضوری (خشوع) کے ساتھ۔ آپ اللہ کے سامنے کھڑے ہونے والے ہیں، جیسے نبی ﷺ شبِ معراج میں اس کے سامنے کھڑے ہوئے تھے۔`, ben: `কিবলার দিকে মুখ করে দাঁড়ান, অর্থাৎ মক্কায় কাবার দিক। এটি ফরজ; ইচ্ছাকৃতভাবে ভুল দিকে মুখ করা নামাজকে বাতিল করে। সোজা হয়ে দাঁড়ান, পা প্রায় কাঁধের সমান প্রস্থে, পূর্ণ অন্তরের উপস্থিতি (খুশু) সহ। আপনি আল্লাহর সামনে দাঁড়াতে চলেছেন, যেমন নবী ﷺ মিরাজের রাতে তাঁর সামনে দাঁড়িয়েছিলেন।`, fas: `رو به قبله، یعنی جهت کعبه در مکه بایست. این واجب است؛ روی گرداندن عمدی به جهت اشتباه نماز را باطل می‌کند. راست بایست، پاها تقریباً به اندازه عرض شانه، با حضور کامل قلب (خشوع). تو در پیشگاه خدا خواهی ایستاد، چنانکه پیامبر ﷺ در شب معراج در پیشگاه او ایستاد.`, zh: `面向基卜萊（即麥加之天房）方向站立。此乃主命；故意背朝錯誤方向則禮拜無效。直身而立，雙足約與肩同寬，懷以完全之專心（虛靜）。你即將立於真主之前，正如先知ﷺ於登霄之夜立於祂之前。`, yue: `面向基卜萊（即麥加之天房）方向站立。此乃主命；故意背朝錯誤方向則禮拜無效。直身而立，雙足約與肩同寬，懷以完全之專心（虛靜）。你即將立於真主之前，正如先知ﷺ於登霄之夜立於祂之前。`, ja: `マッカのカアバの方角であるキブラに向いて立つ。これは義務である。故意に誤った方向に向くと礼拝は無効になる。背筋を伸ばし、足を肩幅ほどに開き、心の完全な臨在（フシュー）をもって立つ。あなたは今、ミウラージュの夜に預言者ﷺが御前に立たれたように、アッラーの御前に立とうとしている。`, ru: `Встань лицом к Кибле  –  направлению Каабы в Мекке. Это обязательно; намеренный поворот в неверную сторону делает намаз недействительным. Стой прямо, ступни примерно на ширине плеч, с полным присутствием сердца (хушуъ). Ты вот-вот предстанешь пред Аллахом, как предстоял Пророк ﷺ в Ночь Вознесения.`, es: `Ponte de pie orientado hacia la Qibla, la dirección de la Ka'bah en La Meca. Esto es obligatorio; orientarse deliberadamente en la dirección equivocada invalida la oración. Mantente erguido, los pies separados aproximadamente al ancho de los hombros, con plena presencia del corazón (khushu'). Estás a punto de ponerte de pie ante Allah, tal como el Profeta ﷺ se puso de pie ante Él durante el Viaje Nocturno.`, ko: `메카에 있는 카바의 방향인 끼블라를 향해 서십시오. 이는 의무이며, 고의로 잘못된 방향을 향하면 예배가 무효가 됩니다. 어깨너비 정도로 발을 벌리고 똑바로 서며, 온전한 마음의 임재(쿠슈우)를 지니십시오. 당신은 예언자 ﷺ께서 미라즈의 밤에 그분 앞에 서신 것처럼, 알라 앞에 서려는 참입니다.`, ta: `மக்காவில் உள்ள கஅபாவின் திசையான கிப்லாவை நோக்கி நில்லுங்கள். இது கடமை; வேண்டுமென்றே தவறான திசையை நோக்குவது தொழுகையை அபாயமாக்குகிறது. நேராக நில்லுங்கள், கால்கள் தோள் அகலத்துக்கு ஏற்றவாறு, இதயத்தின் முழு பிரசன்னத்துடன் (குஷூஃ). நபி ﷺ அவர்கள் இஸ்ரா இரவில் இறைவன் முன்னிலையில் நின்றதைப் போல, நீங்கள் இப்போது அல்லாஹ்வுக்கு முன் நிற்கப் போகிறீர்கள்.`, si: `මක්කා හි කඃබාවේ දිශාව වන කිබ්ලාවට මුහුණලා නැගිට සිටින්න. මෙය අනිවාර්යය; අරමුණෙන් වැරදි දිශාවට මුහුණලීම සලාතය අවලංගු කරයි. කොන්ද කෙළින් සිට, පාද කරවැලෙ පළල පමණ දුරින් තබා, සිතේ සම්පූර්ණ පැමිණීමක් (ඛුෂූඃ) ඇතිව සිටින්න. ඔබ දැන් අල්ලාහ් ඉදිරියේ සිටීමට යයි, මඃරාජ් රාත්‍රියේ නබි ﷺ ඔහු ඉදිරියේ සිටි පරිද්දෙන්ම.` },

  step2_t: { en: `Intention (Niyyah)`, ms: `Niat`, tur: `Niyet`, urd: `نیت`, ben: `নিয়ত`, fas: `نیت`, zh: `舉意（尼亞）`, yue: `舉意（尼亞）`, ja: `意図（ニーヤ）`, ru: `Намерение (Ниййя)`, es: `Intención (Niyyah)`, ko: `의도 (니야)`, ta: `எண்ணம் (நிய்யத்)`, si: `අරමුණ (නිය්‍යා)` },
  step2_d: { en: `Make the intention in your heart for the specific prayer you are about to perform. The intention does not need to be spoken aloud, though some scholars permit it. For example: "I intend to pray two units of Fajr prayer for Allah." The intention is a condition of every act of worship in Islam: it distinguishes worship from habit.`, ms: `Niatkan dalam hati solat tertentu yang akan kamu tunaikan. Niat tidak perlu disebut secara nyaring, walaupun sebahagian ulama membenarkan. Contoh: "Aku berniat solat dua rakaat Subuh kerana Allah." Niat adalah syarat pada setiap ibadah dalam Islam: ia membezakan ibadah daripada kebiasaan.`, tur: `Kılacağın belirli namaz için kalbinden niyet et. Niyetin sesli söylenmesi gerekmez, bazı âlimler buna izin verse de. Örneğin: "Allah için iki rekât sabah namazını kılmaya niyet ettim." Niyet, İslam'daki her ibadetin şartıdır: ibadeti alışkanlıktan ayırır.`, urd: `جس مخصوص نماز کو ادا کرنے والے ہیں اس کی نیت دل میں کریں۔ نیت کا زبان سے کہنا ضروری نہیں، اگرچہ بعض علماء اس کی اجازت دیتے ہیں۔ مثلاً: "میں اللہ کے لیے فجر کی دو رکعت نماز کی نیت کرتا ہوں۔" نیت اسلام میں ہر عبادت کی شرط ہے: یہ عبادت کو عادت سے ممتاز کرتی ہے۔`, ben: `যে নির্দিষ্ট নামাজ আদায় করতে যাচ্ছেন তার নিয়ত মনে করুন। নিয়ত উচ্চস্বরে বলার প্রয়োজন নেই, যদিও কিছু আলিম তা অনুমতি দেন। উদাহরণ: "আমি আল্লাহর উদ্দেশ্যে ফজরের দুই রাকাত নামাজের নিয়ত করছি।" নিয়ত ইসলামে প্রতিটি ইবাদতের শর্ত: এটি ইবাদতকে অভ্যাস থেকে পৃথক করে।`, fas: `برای نماز معینی که در شرف ادای آنی، در دل خود نیت کن. نیت لازم نیست با صدای بلند گفته شود، اگرچه برخی علما اجازه می‌دهند. برای نمونه: "نیت می‌کنم دو رکعت نماز فجر را برای خدا بخوانم." نیت شرط هر عبادت در اسلام است: عبادت را از عادت جدا می‌سازد.`, zh: `心中為即將舉行之特定拜功舉意。舉意無需出聲，雖部分學者允許之。例如：「我為真主舉意禮兩拜晨禮。」舉意乃伊斯蘭中每項功修之條件：將功修與習慣分別開來。`, yue: `心中為即將舉行之特定拜功舉意。舉意無需出聲，雖部分學者允許之。例如：「我為真主舉意禮兩拜晨禮。」舉意乃伊斯蘭中每項功修之條件：將功修與習慣分別開來。`, ja: `これから行う特定の礼拝に対する意図を心に定める。意図は声に出す必要はないが、それを許す学者もいる。例：「アッラーのために朝の礼拝二ラクアを行う意図をする。」意図はイスラムにおけるあらゆる崇拝行為の条件である：崇拝を習慣から区別するものだ。`, ru: `Сделай в сердце намерение совершить именно ту молитву, к которой приступаешь. Произносить намерение вслух не требуется, хотя некоторые учёные допускают это. Например: «Намереваюсь совершить два раката утренней молитвы ради Аллаха.» Намерение  –  условие каждого поклонения в Исламе: оно отличает поклонение от привычки.`, es: `Haz la intención en tu corazón para la oración concreta que vas a realizar. La intención no necesita pronunciarse en voz alta, aunque algunos sabios lo permiten. Por ejemplo: "Hago la intención de rezar dos rak'ahs del Fajr por Allah." La intención es condición de todo acto de adoración en el Islam: distingue la adoración del hábito.`, ko: `행할 특정 예배에 대한 의도를 마음에 두십시오. 의도는 소리 내어 말할 필요는 없으나, 일부 학자들은 그것을 허용합니다. 예: "알라를 위해 파즈르 예배 두 라카를 드릴 의도를 합니다." 의도는 이슬람의 모든 예배의 조건이며, 예배를 습관과 구별짓습니다.`, ta: `நீங்கள் ஆற்றப்போகும் குறிப்பிட்ட தொழுகைக்கான எண்ணத்தை இதயத்தில் கொள்ளுங்கள். எண்ணத்தை சத்தமாக சொல்லத் தேவை இல்லை, சில அறிஞர்கள் அதை அனுமதிக்கின்றனர். எடுத்துக்காட்டாக: "அல்லாஹ்வுக்காக ஃபஜ்ர் தொழுகையின் இரண்டு ரக்அத்துகளைத் தொழ எண்ணுகிறேன்." எண்ணம் இஸ்லாமின் ஒவ்வொரு வழிபாட்டின் நிபந்தனை: அது வழிபாட்டை பழக்கத்திலிருந்து வேறுபடுத்துகிறது.`, si: `ඔබ ඉටු කරන්නට යන විශේෂිත සලාතය සඳහා සිතේ අරමුණ පිහිටුවන්න. අරමුණ හඬ නඟා කීමට අවශ්‍ය නැත, සමහර විද්වතුන් එයට අවසර දුන්නද. උදාහරණයක්: "අල්ලාහ් වෙනුවෙන් ෆජ්ර් සලාතයේ රකඅත් දෙකක් ඉටු කිරීමට මම අරමුණ පිහිටුවමි." අරමුණ ඉස්ලාමයේ සෑම නැමදුමක්ම සඳහා කොන්දේසියකි: එය නැමදුම පුරුද්දෙන් වෙන් කරයි.` },

  step3_t: { en: `Opening Takbir (Takbirat al-Ihram)`, ms: `Takbir Pembukaan (Takbiratul Ihram)`, tur: `İftitah Tekbiri (Tekbîrü'l-İhrâm)`, urd: `تکبیرِ تحریمہ`, ben: `প্রারম্ভিক তাকবির (তাকবিরাতুল ইহরাম)`, fas: `تکبیرة الاحرام (تکبیر آغازین)`, zh: `開拜大讚（伊赫拉姆之大讚）`, yue: `開拜大讚（伊赫拉姆之大讚）`, ja: `開始のタクビール（タクビーラトゥル＝イフラーム）`, ru: `Вступительный такбир (Такбират аль-Ихрам)`, es: `Takbir de apertura (Takbirat al-Ihram)`, ko: `시작의 타크비르 (타크비라툴 이흐람)`, ta: `தொடக்க தக்பீர் (தக்பீரத்துல் இஹ்ராம்)`, si: `ආරම්භක තක්බීර් (තක්බීරතුල් ඉහ්රාම්)` },
  step3_d: { en: `Raise both hands to the earlobes (men) or shoulders (women), palms forward, and say the opening takbir. This marks the formal beginning. Once said, all speech and movement outside of prayer is forbidden, hence 'Ihram' (entering the state of sanctity). Lower the hands and place the right hand over the left on the chest.`, ms: `Angkat kedua-dua tangan setentang cuping telinga (lelaki) atau bahu (wanita), tapak menghadap ke hadapan, lalu sebut takbir pembukaan. Ini menandai permulaan rasmi. Setelah disebut, semua pertuturan dan pergerakan di luar solat diharamkan, kerana itu disebut 'Ihram' (memasuki keadaan kesucian). Turunkan tangan dan letakkan tangan kanan di atas tangan kiri di dada.`, tur: `İki eli kulak yumuşaklarına (erkekler) ya da omuzlara (kadınlar) kaldır, avuçlar öne, ve iftitah tekbirini söyle. Bu, namazın resmi başlangıcıdır. Bir kez söylendiğinde, namaz dışı her söz ve hareket yasaktır; bu nedenle 'İhram' (hürmet hâline girmek) denir. Elleri indir ve sağ eli sol elin üzerine göğüs üzerine koy.`, urd: `دونوں ہاتھ کانوں کی لو (مرد) یا کندھوں (عورت) تک اٹھائیں، ہتھیلیاں سامنے کی طرف، اور تکبیرِ تحریمہ کہیں۔ یہ نماز کا باضابطہ آغاز ہے۔ کہنے کے بعد نماز کے علاوہ تمام گفتگو اور حرکت ممنوع ہو جاتی ہے، اسی لیے اسے 'احرام' (حرمت کی حالت میں داخل ہونا) کہا جاتا ہے۔ ہاتھ نیچے لائیں اور دائیاں ہاتھ بائیں ہاتھ پر سینے پر رکھیں۔`, ben: `উভয় হাত কানের লতি (পুরুষ) বা কাঁধ (নারী) পর্যন্ত উঠান, হাতের তালু সামনের দিকে, এবং প্রারম্ভিক তাকবির বলুন। এটি নামাজের আনুষ্ঠানিক সূচনা। বলার পর নামাজের বাইরে সকল কথা ও নড়াচড়া নিষিদ্ধ হয়ে যায়, এ কারণে এটিকে 'ইহরাম' (পবিত্রতার অবস্থায় প্রবেশ) বলা হয়। হাত নামিয়ে এনে ডান হাত বাম হাতের উপরে বুকের উপর রাখুন।`, fas: `هر دو دست را تا نرمه گوش (مردان) یا شانه‌ها (زنان) بلند کن، کف دست‌ها رو به جلو، و تکبیر آغاز را بگو. این آغاز رسمی نماز است. پس از گفتن آن، هر سخن و حرکت خارج از نماز حرام می‌شود، از این رو 'احرام' (ورود به حالت حرمت) نامیده می‌شود. دست‌ها را پایین بیاور و دست راست را بر دست چپ بر روی سینه قرار ده.`, zh: `將雙手舉至耳垂（男）或肩部（女），掌心向前，誦開拜大讚。此即禮拜之正式開始。一經誦出，禮拜以外之言語動作皆被禁止，故名'伊赫拉姆'（進入聖潔之態）。將手放下，右手置於左手之上於胸前。`, yue: `將雙手舉至耳垂（男）或肩部（女），掌心向前，誦開拜大讚。此即禮拜之正式開始。一經誦出，禮拜以外之言語動作皆被禁止，故名'伊赫拉姆'（進入聖潔之態）。將手放下，右手置於左手之上於胸前。`, ja: `両手を耳たぶ（男性）または肩（女性）の高さまで挙げ、手のひらを前に向けて開始のタクビールを唱える。これが礼拝の正式な始まりである。これを唱えた瞬間から礼拝外のあらゆる発話と動作は禁じられ、ゆえに「イフラーム」（聖なる状態に入ること）と呼ばれる。手を下ろし、右手を左手の上に重ねて胸の上に置く。`, ru: `Подними обе руки до мочек ушей (мужчины) или плеч (женщины), ладонями вперёд, и произнеси вступительный такбир. Это формальное начало намаза. После него любая речь и движение вне намаза запрещены, отсюда название «Ихрам» (вступление в состояние освящённости). Опусти руки и положи правую руку поверх левой на груди.`, es: `Levanta ambas manos hasta los lóbulos de las orejas (hombres) o los hombros (mujeres), con las palmas hacia adelante, y di el takbir de apertura. Esto marca el comienzo formal. Una vez dicho, toda palabra y movimiento ajenos a la oración están prohibidos, por eso se llama 'Ihram' (entrar en estado de santidad). Baja las manos y coloca la derecha sobre la izquierda sobre el pecho.`, ko: `양손을 귀불(남자) 또는 어깨(여자) 높이로 손바닥을 앞으로 향하게 들고 시작의 타크비르를 외친다. 이것이 예배의 공식적 시작이다. 한 번 외친 뒤에는 예배 외의 모든 말과 행동이 금지되며, 그래서 '이흐람'(거룩의 상태로 들어감)이라 한다. 손을 내려 오른손을 왼손 위에 가슴 위에 둔다.`, ta: `இரு கைகளையும் காதின் மென்மையான பகுதி (ஆண்) அல்லது தோள் (பெண்) வரை, உள்ளங்கைகள் முன்னோக்கி, உயர்த்தி தொடக்க தக்பீரைக் கூறுங்கள். இது தொழுகையின் முறையான தொடக்கம். ஒருமுறை கூறிய பின் தொழுகைக்கு வெளியேயான பேச்சும் அசைவும் தடைசெய்யப்படுகின்றன, அதனால் இது 'இஹ்ராம்' (புனிதத்தின் நிலையில் நுழைதல்) எனப்படுகிறது. கைகளை இறக்கி, வலது கையை இடது கையின் மீது நெஞ்சில் வைக்கவும்.`, si: `දෑත් කන් උක්කු (පුරුෂයන්) හෝ උරහිස් (කාන්තාවන්) දක්වා ඔසවා, අත්ල ඉදිරියට හරවා, ආරම්භක තක්බීර් කියන්න. මෙය සලාතයේ විධිමත් ආරම්භයයි. එය කී පසු සලාතයෙන් පිට වූ සියලු කථාබහ සහ චලනය තහනම් වේ; එනිසා එය 'ඉහ්රාම්' (පූජනීය තත්ත්වයට ඇතුළු වීම) ලෙස හැඳින්වේ. දෑත් පහත් කර, දකුණු අත වම් අත මත පපුව මත තබන්න.` },
  step3_translit:{ en: `Allahu Akbar` },
  step3_meaning: { en: `Allah is greater (than everything in this world and in one's mind).`, ms: `Allah Maha Besar (daripada segala sesuatu di dunia ini dan di dalam fikiran seseorang).`, tur: `Allah, bu dünyadaki ve insanın aklındaki her şeyden daha büyüktür.`, urd: `اللہ سب سے بڑا ہے (اس دنیا اور انسان کے ذہن میں موجود ہر چیز سے)۔`, ben: `আল্লাহ মহান (এই দুনিয়ার এবং মানুষের মনে থাকা সবকিছু থেকে)।`, fas: `خداوند بزرگ‌تر است (از هر آنچه در این دنیا و در ذهن انسان است).`, zh: `真主比此世與心中之一切皆更尊大。`, yue: `真主比此世與心中之一切皆更尊大。`, ja: `アッラーはこの世のすべてのものよりも、また人の心に浮かぶいかなるものよりも至大なり。`, ru: `Аллах превыше всего, что есть в этом мире и в уме человека.`, es: `Allah es más grande (que todo cuanto hay en este mundo y en la mente del ser humano).`, ko: `알라께서는 이 세상의 모든 것보다, 그리고 사람의 마음속의 어떤 것보다 위대하시다.`, ta: `அல்லாஹ் இவ்வுலகில் உள்ள மற்றும் மனிதனின் மனத்தில் உள்ள அனைத்தையும் விட பெரியவன்.`, si: `අල්ලාහ් මේ ලෝකයේ ඇති සියල්ලටත් මනුෂ්‍යයකුගේ සිතේ ඇති ඕනෑම දෙයකටත් වඩා ශ්‍රේෂ්ඨය.` },

  step4_t: { en: `Opening Supplication (Du'a al-Istiftah)`, ms: `Doa Pembukaan (Doa al-Istiftah)`, tur: `Açılış Duası (Duâ-i İstiftâh)`, urd: `دعائے استفتاح`, ben: `প্রারম্ভিক দোয়া (দু'আ আল-ইস্তিফতাহ)`, fas: `دعای استفتاح (دعای آغازین)`, zh: `開拜祈禱詞（杜阿‧伊斯提弗塔）`, yue: `開拜祈禱詞（杜阿‧伊斯提弗塔）`, ja: `開始の祈り（ドゥアー・アル＝イスティフターフ）`, ru: `Вступительная мольба (Дуа аль-Истифтах)`, es: `Súplica de apertura (Du'a al-Istiftah)`, ko: `시작의 두아 (두아 알이스티프타흐)`, ta: `தொடக்க துஆ (துஆ அல்-இஸ்திஃப்தாஹ்)`, si: `ආරම්භක දුආව (දුආ අල්-ඉස්තිෆ්තාහ්)` },
  step4_d: { en: `Recite the opening supplication silently. Two versions are reported from the Prophet ﷺ. The Subhanaka version is most widely practised. The Allahumma ba'id version is from Muslim 598 and the Prophet ﷺ used it in the night prayer. Both are valid:`, ms: `Baca doa pembukaan secara senyap. Dua versi diriwayatkan daripada Nabi ﷺ. Versi Subhanaka adalah yang paling meluas diamalkan. Versi Allahumma ba'id daripada Muslim 598, dan Nabi ﷺ membacanya dalam solat malam. Kedua-duanya sahih:`, tur: `İftitah duasını sessizce oku. Peygamber'den ﷺ iki rivayet vardır. Sübhâneke versiyonu en yaygın uygulananıdır. Allahümme bâ'id versiyonu Müslim 598'dendir; Peygamber ﷺ onu gece namazında okurdu. İkisi de sahihtir:`, urd: `دعائے استفتاح آہستہ پڑھیں۔ نبی ﷺ سے دو روایتیں ثابت ہیں۔ سُبْحٰنَكَ والی روایت سب سے زیادہ رائج ہے۔ اللَّهُمَّ بَاعِدْ والی روایت مسلم ۵۹۸ سے ہے اور نبی ﷺ اسے رات کی نماز میں پڑھتے تھے۔ دونوں صحیح ہیں:`, ben: `প্রারম্ভিক দোয়া নীরবে পড়ুন। নবী ﷺ থেকে দুটি বর্ণনা প্রমাণিত। সুবহানাকা সংস্করণটি সবচেয়ে ব্যাপকভাবে প্রচলিত। আল্লাহুম্মা বা'ইদ সংস্করণটি মুসলিম ৫৯৮ থেকে এবং নবী ﷺ এটি রাতের নামাজে পড়তেন। উভয়ই সহিহ:`, fas: `دعای استفتاح را آرام بخوان. از پیامبر ﷺ دو روایت رسیده است. روایت سبحانک رایج‌ترین است. روایت اللهم باعد از مسلم ۵۹۸ است و پیامبر ﷺ آن را در نماز شب می‌خواند. هر دو صحیح‌اند:`, zh: `輕聲誦開拜祈禱詞。先知ﷺ傳下二式：以「Subhanaka」開始之式最為通行；以「Allahumma ba'id」開始之式出自《穆斯林聖訓》598，先知ﷺ於夜禮中誦之。二者皆為正傳：`, yue: `輕聲誦開拜祈禱詞。先知ﷺ傳下二式：以「Subhanaka」開始之式最為通行；以「Allahumma ba'id」開始之式出自《穆斯林聖訓》598，先知ﷺ於夜禮中誦之。二者皆為正傳：`, ja: `開始の祈りを黙誦する。預言者ﷺから二つの伝承が伝わっている。スブハーナカの版が最も広く行われている。アッラーフンマ・バーイドの版はムスリム598に伝わり、預言者ﷺは夜の礼拝で唱えられた。両方とも正統である：`, ru: `Прочти вступительную мольбу про себя. От Пророка ﷺ передаются две версии. Версия «Субханака» наиболее распространена. Версия «Аллахумма ба'ид» приведена в Муслим 598, и Пророк ﷺ читал её в ночной молитве. Обе достоверны:`, es: `Recita la súplica de apertura en silencio. Se reportan dos versiones del Profeta ﷺ. La versión "Subhanaka" es la más practicada. La versión "Allahumma ba'id" está en Muslim 598 y el Profeta ﷺ la usaba en la oración nocturna. Ambas son válidas:`, ko: `시작의 두아를 조용히 낭송하라. 예언자 ﷺ로부터 두 가지 판본이 전해진다. "수브하나카" 판본이 가장 널리 사용된다. "알라훔마 바이드" 판본은 무슬림 598에 있으며 예언자 ﷺ께서 밤 예배에서 사용하셨다. 둘 다 진본이다:`, ta: `தொடக்க துஆவை அமைதியாக ஓதுங்கள். நபி ﷺ அவர்களிடமிருந்து இரண்டு பாடம் அறிவிக்கப்பட்டுள்ளன. ஸுப்ஹானக பாடம் மிக பரவலாக நடைமுறையில் உள்ளது. அல்லாஹும்ம பஃஇத் பாடம் முஸ்லிம் 598-ல் உள்ளது மற்றும் நபி ﷺ அவர்கள் இதை இரவுத் தொழுகையில் பயன்படுத்தினார்கள். இரண்டும் சரியானவை:`, si: `ආරම්භක දුආව නිහඬව කියවන්න. නබි ﷺ ගෙන් සංස්කරණ දෙකක් වාර්තා වී ඇත. "සුබ්හානක" සංස්කරණය වඩාත් පුළුල්ව භාවිතා වේ. "අල්ලාහුම්ම බාඉද්" සංස්කරණය මුස්ලිම් 598 හි ඇති අතර, නබි ﷺ එය රාත්‍රී සලාතයේදී කියවූහ. දෙකම නිවැරදිය:` },
  step4_translit:{ en: `Subhanakal-lahumma wa bihamdika wa tabarakas-muka wa ta'ala jadduka wa la ilaha ghairuk` },
  step4_meaning: { en: `Glory be to You, O Allah, and praise be to You. Blessed is Your name, exalted is Your majesty, and there is no god but You.`, ms: `Maha Suci Engkau, ya Allah, dan segala pujian bagi-Mu. Maha Berkat nama-Mu, Maha Tinggi keagungan-Mu, dan tiada tuhan selain Engkau.`, tur: `Sen her türlü noksanlıktan münezzehsin Allah'ım, hamd Sana'dır. İsmin mübarek, şânın yücedir, Senden başka ilâh yoktur.`, urd: `پاک ہے تو اے اللہ، اور تیری ہی حمد ہے۔ بابرکت ہے تیرا نام، بلند ہے تیری شان، اور تیرے سوا کوئی معبود نہیں۔`, ben: `পবিত্র তুমি, হে আল্লাহ, এবং তোমারই প্রশংসা। বরকতময় তোমার নাম, সমুন্নত তোমার মহিমা, এবং তুমি ছাড়া কোনো উপাস্য নেই।`, fas: `پاک و منزهی تو ای خدا، و ستایش از آنِ توست. مبارک باد نام تو، بلند باد جلال تو، و معبودی جز تو نیست.`, zh: `主啊，讚頌祢清淨無瑕，一切讚頌歸於祢。祢的名應受讚美，祢的尊嚴至高無上，除祢之外絕無應受崇拜者。`, yue: `主啊，讚頌祢清淨無瑕，一切讚頌歸於祢。祢的名應受讚美，祢的尊嚴至高無上，除祢之外絕無應受崇拜者。`, ja: `アッラーよ、あなたに栄光あれ、あなたに称えあれ。あなたの御名は祝されたものなり、あなたの威光は至高なり、あなたのほかに神はなし。`, ru: `Слава Тебе, о Аллах, и хвала Тебе. Благословенно имя Твоё, превознесено величие Твоё, и нет божества, кроме Тебя.`, es: `Glorificado seas, oh Allah, y alabado seas. Bendito sea Tu nombre, exaltada Tu majestad, y no hay dios sino Tú.`, ko: `오 알라여, 당신께 영광이 있으소서, 당신께 찬양이 있으소서. 당신의 이름은 축복받으시며, 당신의 위엄은 드높으시며, 당신 외에 신은 없나이다.`, ta: `அல்லாஹ்வே, உனக்கே துதி, உனக்கே புகழ். உனது பெயர் வரப்பிரசாதம் பெற்றது, உனது மகிமை மிக உயர்ந்தது, மற்றும் உன்னைத் தவிர வணக்கத்திற்குரியவன் இல்லை.`, si: `අල්ලාහ්, ඔබට ස්තුති වේවා, ඔබට ප්‍රශංසා වේවා. ඔබේ නාමය ආශීර්වාද ලත්ය, ඔබේ මහිමය උසස්ය, සහ ඔබ හැර වෙනත් දෙවියෙකු නැත.` },
  step4_xlabel:  { en: `Alternative opening supplication (Muslim 598):` },
  step4_xtranslit:{ en: `Allahumma ba'id bayni wa bayna khatayaya kama ba'adta baynal-mashriqi wal-maghrib. Allahumma naqqini min khatayaya kama yunaqqath-thawbul-abyadu minad-danas. Allahummaghsilni min khatayaya bith-thalji wal-ma'i wal-barad.` },
  step4_xmeaning:{ en: `O Allah, put distance between me and my sins as You have put distance between East and West. O Allah, cleanse me of my sins as a white garment is cleansed of filth. O Allah, wash away my sins with snow, water, and hail.` },

  step5_t: { en: `Al-Fatiha and Additional Surah`, ms: `Al-Fatihah dan Surah Tambahan`, tur: `Fâtiha ve Zammı Sûre`, urd: `سورۃ الفاتحہ اور سورت ضم`, ben: `সূরা ফাতিহা ও অতিরিক্ত সূরা`, fas: `سوره فاتحه و سوره دیگر`, zh: `《開端章》與附加章`, yue: `《開端章》與附加章`, ja: `開扉章（ファーティハ）と追加の章`, ru: `Аль-Фатиха и дополнительная сура`, es: `Al-Fátiha y una sura adicional`, ko: `알파티하와 추가 장(수라)`, ta: `அல்-ஃபாதிஹா மற்றும் கூடுதல் சூரா`, si: `අල්-ෆාතිහා සහ අතිරේක සූරාව` },
  step5_d: { en: `Recite A'udhu billahi mina-sh-shaytanir-rajim and Bismillah (both silently), then recite Surah al-Fatiha. This is a pillar of every unit: the prayer of one who does not recite it is invalid (Bukhari, Muslim). Say "Amin" aloud in congregation or quietly alone. Then recite any surah from the Qur'an; the Prophet ﷺ always recited an additional surah in the first two units. Longer surahs in Fajr, shorter in other prayers. This additional surah is Sunnah Mu'akkadah.`, ms: `Baca A'udhu billahi minash-shaitanir-rajim dan Bismillah (kedua-duanya senyap), kemudian baca Surah al-Fatihah. Ini adalah rukun setiap rakaat: solat orang yang tidak membacanya tidak sah (Bukhari, Muslim). Sebut "Amin" dengan kuat dalam jemaah atau perlahan jika sendiri. Kemudian baca mana-mana surah dari Al-Quran; Nabi ﷺ sentiasa membaca surah tambahan dalam dua rakaat pertama. Surah panjang di Subuh, lebih pendek di solat lain. Surah tambahan ini ialah Sunnah Mu'akkadah.`, tur: `A'ûzü billâhi mineşşeytâni'r-racîm ve Besmele'yi (her ikisi de gizli) oku, sonra Fâtiha sûresini oku. Bu, her rekâtın rüknüdür: okumayanın namazı sahih değildir (Buhârî, Müslim). Cemaatte yüksek sesle, yalnızken alçak sesle "Âmin" de. Sonra Kur'an'dan herhangi bir sûre oku; Peygamber ﷺ ilk iki rekâtta her zaman ek bir sûre okurdu. Sabah'ta uzun, diğer namazlarda kısa sûreler. Bu ek sûre Sünnet-i Müekkede'dir.`, urd: `أعوذ بالله من الشيطان الرجيم اور بسم اللہ (دونوں سراً) پڑھیں، پھر سورۃ الفاتحہ پڑھیں۔ یہ ہر رکعت کا رکن ہے: جو نہ پڑھے اس کی نماز نہیں ہوتی (بخاری، مسلم)۔ جماعت میں "آمین" بلند آواز سے یا اکیلے میں آہستہ کہیں۔ پھر قرآن سے کوئی سورت پڑھیں؛ نبی ﷺ پہلی دو رکعتوں میں ہمیشہ ایک اضافی سورت پڑھتے تھے۔ فجر میں لمبی سورتیں، دیگر نمازوں میں چھوٹی۔ یہ اضافی سورت سنّتِ مؤکدہ ہے۔`, ben: `আউযুবিল্লাহি মিনাশ শাইতানির রজীম ও বিসমিল্লাহ (উভয়ই নীরবে) পড়ুন, এরপর সূরা ফাতিহা পড়ুন। এটি প্রতিটি রাকাতের রুকন: যে পড়ে না তার নামাজ শুদ্ধ নয় (বুখারি, মুসলিম)। জামাতে উচ্চস্বরে এবং একাকী নীরবে "আমিন" বলুন। এরপর কুরআন থেকে যেকোনো সূরা পড়ুন; নবী ﷺ প্রথম দুই রাকাতে সর্বদাই একটি অতিরিক্ত সূরা পড়তেন। ফজরে দীর্ঘ সূরা, অন্য নামাজে ছোট। এই অতিরিক্ত সূরা সুন্নাহে মুআক্কাদা।`, fas: `أعوذ بالله من الشیطان الرجیم و بسم الله را (هر دو آرام) بخوان، سپس سوره فاتحه را بخوان. این رکن هر رکعت است: نماز کسی که آن را نخواند صحیح نیست (بخاری، مسلم). در جماعت "آمین" را با صدای بلند و در نماز فردی آرام بگو. سپس هر سوره‌ای از قرآن بخوان؛ پیامبر ﷺ همواره در دو رکعت اول سوره‌ای افزون می‌خواند. در فجر سوره‌های بلند، در سایر نمازها کوتاه‌تر. این سوره افزوده سنت مؤکد است.`, zh: `先低聲誦『我求真主庇佑，免遭被棄絕之惡魔』與『奉真主之名』，繼之誦《開端章》。此乃每拜之主柱：未誦者其拜功無效（布哈里、穆斯林）。集體禮拜時高聲、獨自時低聲說『阿敏』。然後誦《古蘭》中任何一章；先知ﷺ每於前兩拜皆誦附加之章。晨禮取長章，其餘各拜取短章。此附加章為強調聖行。`, yue: `先低聲誦『我求真主庇佑，免遭被棄絕之惡魔』與『奉真主之名』，繼之誦《開端章》。此乃每拜之主柱：未誦者其拜功無效（布哈里、穆斯林）。集體禮拜時高聲、獨自時低聲說『阿敏』。然後誦《古蘭》中任何一章；先知ﷺ每於前兩拜皆誦附加之章。晨禮取長章，其餘各拜取短章。此附加章為強調聖行。`, ja: `アウーズビッラーヒ・ミナッシャイターニ・ッラジームとビスミッラー（共に黙誦）を唱え、続いて開扉章（ファーティハ）を誦する。これは各ラクアの柱である：唱えない者の礼拝は無効（ブハーリー、ムスリム）。集団礼拝では声に出して、単独では静かに「アーミーン」と言う。次にクルアーンから任意の章を誦する；預言者ﷺは最初の二ラクアでは常に追加の章を読まれた。ファジュルでは長い章、他の礼拝ではより短い章を。この追加の章は確認されたスンナ（スンナ・ムアッカダ）である。`, ru: `Произнеси Аʿузу билляхи мина-ш-шайтани-р-раджим и Бисмиллях (оба про себя), затем прочти суру аль-Фатиха. Это столп каждого раката: молитва того, кто её не прочёл, недействительна (Бухари, Муслим). Скажи «Амин» вслух в общине или тихо, если один. Затем прочти любую суру из Корана; Пророк ﷺ всегда читал дополнительную суру в первых двух ракатах. В Фаджре длинные суры, в остальных намазах короче. Эта дополнительная сура  –  Сунна Муаккада.`, es: `Recita A'udhu billahi mina-sh-shaytanir-rajim y Bismillah (ambos en silencio), luego recita la Surah al-Fatiha. Es pilar de cada rak'ah: la oración de quien no la recita es inválida (Bujari, Muslim). Di "Amin" en voz alta en congregación o quedo si rezas solo. Después recita cualquier sura del Corán; el Profeta ﷺ siempre recitaba una sura adicional en los dos primeros rak'ahs. Suras largas en el Fajr, más cortas en los demás. Esta sura adicional es Sunnah Mu'akkadah.`, ko: `아우주빌라히 미나쉬샤이타닐라짐과 비스밀라(둘 다 소리 없이)를 낭송한 후, 알파티하 장을 낭송한다. 이는 각 라카의 기둥이다: 낭송하지 않는 자의 예배는 무효이다(부카리, 무슬림). 회중 예배에서는 큰 소리로, 혼자일 때는 조용히 "아민"을 말한다. 그다음 꾸란의 어떤 장이든 낭송한다; 예언자 ﷺ께서는 첫 두 라카에서 항상 추가 장을 낭송하셨다. 파즈르에서는 긴 장, 다른 예배에서는 짧은 장. 이 추가 장은 순나 무앗카다이다.`, ta: `அஊது பில்லாஹி மினஷ் ஷைதானிர் ரஜீம் மற்றும் பிஸ்மில்லாஹ் (இரண்டையும் அமைதியாக) ஓதி, பின் சூரத்துல் ஃபாதிஹா ஓதுங்கள். இது ஒவ்வொரு ரக்அத்தின் ருக்ன்: ஓதாதவரின் தொழுகை செல்லாது (புகாரி, முஸ்லிம்). ஜமாஅத்தில் "ஆமீன்" உரக்க, தனியாக அமைதியாக கூறுங்கள். பின் குர்ஆனிலிருந்து எந்த சூராவையும் ஓதுங்கள்; நபி ﷺ முதல் இரு ரக்அத்களில் எப்போதும் கூடுதல் சூரா ஓதினார். ஃபஜ்ரில் நீளமான சூராக்கள், மற்ற தொழுகைகளில் சுருக்கமானவை. இந்த கூடுதல் சூரா ஸுன்னத்துல் முஅக்கதா.`, si: `අඌදු බිල්ලාහි මිනෂ් ෂයිතානිර් රජීම් සහ බිස්මිල්ලාහ් (දෙකම නිහඬව) කියවා, පසුව සූරා අල්-ෆාතිහා කියවන්න. මෙය සෑම රකඅතයකම කුළුණයි: එය නොකියවන තැනැත්තාගේ සලාතය වලංගු නැත (බුහාරි, මුස්ලිම්). පිරිසක් සමඟ විට "ආමීන්" හඬ නඟා, තනිව විට නිහඬව කියන්න. පසුව කුර්ආනයෙන් ඕනෑම සූරාවක් කියවන්න; නබි ﷺ පළමු රකඅත් දෙකේදී සැමවිටම අතිරේක සූරාවක් කියවූහ. ෆජ්ර්හි දිගු සූරා, අන් සලාතවල කෙටි. මෙම අතිරේක සූරාව සුන්නා මුඅක්කදා වේ.` },
  step5_translit:{ en: `Al-hamdu lillahi rabb il-'alamin. Ar-Rahmanir-Rahim. Maliki yawmid-din. Iyyaka na'budu wa iyyaka nasta'in. Ihdinas-siratal-mustaqim. Siratal-ladhina an'amta 'alayhim, ghayril-maghdubi 'alayhim wa lad-dallin.` },
  step5_meaning: { en: `All praise is for Allah, Lord of all worlds. The Most Compassionate, the Most Merciful. Master of the Day of Judgement. You alone we worship and You alone we ask for help. Guide us along the straight path, the path of those You have blessed, not those You are displeased with, or those who are astray.`, ms: `Segala pujian bagi Allah, Tuhan semesta alam. Maha Pengasih, Maha Penyayang. Yang Menguasai Hari Pembalasan. Hanya Engkau yang kami sembah dan hanya Engkau yang kami pohon pertolongan. Tunjukilah kami jalan yang lurus, jalan orang-orang yang Engkau beri nikmat, bukan jalan mereka yang Engkau murkai, dan bukan jalan mereka yang sesat.`, tur: `Hamd, âlemlerin Rabbi Allah'a mahsustur. Rahman'dır, Rahim'dir. Din gününün hâkimidir. Yalnız Sana ibadet eder, yalnız Senden yardım dileriz. Bizi doğru yola ilet; nimet verdiğin kimselerin yoluna; gazaba uğramışların ve sapmışların yoluna değil.`, urd: `سب تعریف اللہ کے لیے ہے، سارے جہانوں کا پروردگار۔ بے حد رحم کرنے والا، ہمیشہ رحم کرنے والا۔ روزِ جزا کا مالک۔ ہم صرف تیری ہی عبادت کرتے ہیں اور صرف تجھ ہی سے مدد مانگتے ہیں۔ ہمیں سیدھے راستے کی ہدایت دے، ان لوگوں کا راستہ جن پر تو نے انعام کیا، نہ کہ ان کا جن پر غضب ہوا، اور نہ گمراہوں کا۔`, ben: `সমস্ত প্রশংসা আল্লাহর জন্য, যিনি সকল জগতের প্রতিপালক। পরম দয়াময়, অসীম দয়ালু। বিচার দিনের মালিক। আমরা শুধু তোমারই ইবাদত করি এবং শুধু তোমারই সাহায্য চাই। আমাদেরকে সরল পথের হিদায়াত দাও, সেই পথ যাঁদের তুমি অনুগ্রহ করেছ, তাদের পথ নয় যাদের ওপর তোমার ক্রোধ পতিত হয়েছে, এবং পথভ্রষ্টদেরও নয়।`, fas: `ستایش از آنِ خداست، پروردگار جهانیان. بخشاینده، مهربان. خداوند روز جزا. تنها تو را می‌پرستیم و تنها از تو یاری می‌جوییم. ما را به راه راست هدایت کن، راه کسانی که بر آنان نعمت بخشیدی، نه راه آنان که بر آنان غضب کردی و نه گمراهان.`, zh: `一切讚頌全歸真主，眾世界的主。至仁至慈。報應日的主。我們只崇拜祢，只求祢佑助。求祢引導我們上正路，祢所施恩者的路，不是受譴怒者的路，也不是迷誤者的路。`, yue: `一切讚頌全歸真主，眾世界的主。至仁至慈。報應日的主。我們只崇拜祢，只求祢佑助。求祢引導我們上正路，祢所施恩者的路，不是受譴怒者的路，也不是迷誤者的路。`, ja: `万有の主、アッラーに称えあれ。慈悲深く、慈愛遍き御方。審きの日の主宰者。我らはあなただけを崇め、あなただけに助けを求める。我らを正しき道へ導きたまえ、あなたが恵みを与えた者たちの道、あなたの怒りを蒙る者たちの道ではなく、また迷う者たちの道でもなく。`, ru: `Хвала Аллаху, Господу миров. Милостивому, Милосердному. Властелину Дня воздаяния. Тебе одному мы поклоняемся и Тебя одного просим о помощи. Веди нас прямым путём, путём тех, кого Ты облагодетельствовал, а не тех, на кого пал гнев, и не заблудших.`, es: `Toda la alabanza pertenece a Allah, Señor de los mundos. El Compasivo, el Misericordioso. Soberano del Día del Juicio. A Ti solo adoramos y a Ti solo pedimos ayuda. Guíanos por el camino recto, el camino de aquellos a quienes has favorecido, no el de los que han incurrido en Tu ira ni el de los extraviados.`, ko: `모든 찬양은 만유의 주, 알라께 있나이다. 자비로우시고 자애로우신 분. 심판의 날의 주인. 오직 당신만을 우리는 경배하며, 오직 당신께만 우리는 도움을 구하나이다. 우리를 바른 길로 인도하소서, 당신께서 은혜를 베푸신 자들의 길, 진노를 받은 자들의 길도 아니요, 길 잃은 자들의 길도 아니오니이다.`, ta: `எல்லாப் புகழும் அகிலங்களின் இறைவனாகிய அல்லாஹ்வுக்கே. அளவற்ற கருணையாளன், நிகரற்ற கருணை மிக்கவன். தீர்ப்பு நாளின் அதிபதி. உன்னையே நாங்கள் வணங்குகிறோம், உன்னிடமே நாங்கள் உதவி தேடுகிறோம். எங்களை நேரான பாதையில் வழிநடத்துவாயாக, நீ அருள் புரிந்தோரின் பாதை, கோபத்திற்குள்ளானவர்களின் பாதையோ வழிதவறியவர்களின் பாதையோ அல்ல.`, si: `සියලු ප්‍රශංසා සියලු ලෝකවල සමිඳා වූ අල්ලාහ්ට ය. ඉතා කරුණාවන්ත, ඉතා දයාබර. විනිශ්චය දිනයේ අධිපති. ඔබට පමණක් අපි වන්දනා කරමු, ඔබෙන් පමණක් අපි උපකාර පතමු. අපට ඍජු මාර්ගය පෙන්වන්න, ඔබ ආශීර්වාද කළ අයගේ මාර්ගය, කෝපයට ලක් වූ අයගේ ද නොව, මග හැරුණු අයගේ ද නොව.` },

  step6_t: { en: `Bowing (Ruku')`, ms: `Rukuk`, tur: `Rükû (Eğilme)`, urd: `رکوع`, ben: `রুকু`, fas: `رکوع`, zh: `鞠躬（魯庫）`, yue: `鞠躬（魯庫）`, ja: `腰を屈める（ルクー）`, ru: `Поясной поклон (Рукуъ)`, es: `Inclinación (Ruku')`, ko: `허리 굽힘 (루쿠)`, ta: `குனிதல் (ருகூஃ)`, si: `ඉඟටිය නැමීම (රුකූඃ)` },
  step6_d: { en: `Raise the hands and say Allahu Akbar while bending. Place both hands firmly on the knees, fingers spread, back flat and level with the ground. Hold this with complete stillness (tuma'ninah). When "Fasabbih bismi Rabbik al-Azim" (Qur'an 56:96) was revealed, the Prophet ﷺ said: "Make it your ruku' dhikr." Minimum: three times.`, ms: `Angkat tangan dan sebut Allahu Akbar sambil membongkok. Letakkan kedua-dua tangan kuat di atas lutut, jari direnggangkan, belakang rata sejajar dengan lantai. Tahan dengan ketenangan sempurna (tuma'ninah). Apabila ayat "Fasabbih bismi Rabbika al-'Azim" (Al-Quran 56:96) diturunkan, Nabi ﷺ bersabda: "Jadikanlah ia zikir rukukmu." Minimum: tiga kali.`, tur: `Elleri kaldır ve eğilirken Allahu Ekber de. İki eli dizlere sıkıca koy, parmaklar açık, sırt düz ve yere paralel. Bunu tam bir sükûnetle (tuma'nîne) tut. "Fesebbih bismi Rabbike'l-azîm" (Kur'an 56:96) indiğinde Peygamber ﷺ buyurdu: "Onu rükû zikriniz yapın." Asgari: üç kez.`, urd: `ہاتھ اٹھائیں اور جھکتے ہوئے اللہ اکبر کہیں۔ دونوں ہاتھ مضبوطی سے گھٹنوں پر رکھیں، انگلیاں پھیلی ہوئی، کمر سیدھی اور زمین کے متوازی۔ مکمل سکون (طمأنینہ) کے ساتھ اسے تھامیں۔ جب "فَسَبِّحْ بِاسْمِ رَبِّكَ الْعَظِيمِ" (قرآن ۵۶:۹۶) نازل ہوئی تو نبی ﷺ نے فرمایا: "اسے اپنے رکوع کی ذکر بنا لو۔" کم سے کم: تین مرتبہ۔`, ben: `হাত উঠান এবং রুকুতে যাওয়ার সময় আল্লাহু আকবার বলুন। উভয় হাত শক্ত করে হাঁটুর উপর রাখুন, আঙুল ছড়ান, পিঠ সোজা ও মাটির সমান্তরাল। সম্পূর্ণ স্থিরতার (তুমা'নিনাহ) সাথে এ অবস্থায় থাকুন। যখন "ফাসাব্বিহ বিসমি রাব্বিকাল আযীম" (কুরআন ৫৬:৯৬) অবতীর্ণ হলো, নবী ﷺ বললেন: "এটিকে তোমাদের রুকুর যিকর বানাও।" সর্বনিম্ন: তিনবার।`, fas: `دست‌ها را بلند کن و در حال خم شدن الله اکبر بگو. هر دو دست را محکم بر زانوها بگذار، انگشتان باز، پشت صاف و موازی با زمین. این حالت را با آرامش کامل (طمأنینه) نگه دار. هنگامی که "فَسَبِّحْ بِاسْمِ رَبِّكَ الْعَظِيمِ" (قرآن ۵۶:۹۶) نازل شد، پیامبر ﷺ فرمود: "آن را ذکر رکوع خود قرار دهید." حداقل: سه بار.`, zh: `舉手並於彎身時誦『安拉胡阿克巴爾』。雙手堅放於兩膝，五指張開，後背平直與地面相平。當以完全之安寧（圖瑪寧納）守之。當「故你應當以你尊大主之名而讚頌」（古蘭56:96）降示時，先知ﷺ言：「以此作為汝鞠躬之贊念。」至少：三次。`, yue: `舉手並於彎身時誦『安拉胡阿克巴爾』。雙手堅放於兩膝，五指張開，後背平直與地面相平。當以完全之安寧（圖瑪寧納）守之。當「故你應當以你尊大主之名而讚頌」（古蘭56:96）降示時，先知ﷺ言：「以此作為汝鞠躬之贊念。」至少：三次。`, ja: `両手を挙げて、屈むときに「アッラーフ・アクバル」と唱える。両手を膝の上にしっかり置き、指を広げ、背中を平らに地面と平行にする。完全な静止（トゥマアニーナ）でこれを保つ。「あなたの偉大なる主の御名を称えなさい」（クルアーン56:96）が啓示された際、預言者ﷺは仰せられた：「これをあなたがたのルクーのズィクルとせよ。」最少：3回。`, ru: `Подними руки и скажи Аллаху Акбар, наклоняясь. Положи обе руки крепко на колени, пальцы расставлены, спина прямая и параллельная земле. Удерживай это в полной неподвижности (тумаʿнина). Когда был ниспослан аят «Прославляй же имя Господа твоего Великого» (Коран 56:96), Пророк ﷺ сказал: «Сделайте это зикром вашего рукуъ.» Минимум: три раза.`, es: `Levanta las manos y di Allahu Akbar al inclinarte. Coloca ambas manos firmemente sobre las rodillas, los dedos separados, la espalda recta y paralela al suelo. Mantén esto con quietud completa (tuma'ninah). Cuando se reveló "Glorifica el nombre de tu Señor el Inmenso" (Corán 56:96), el Profeta ﷺ dijo: "Hacedlo el dhikr de vuestro ruku'." Mínimo: tres veces.`, ko: `손을 들고 굽히면서 알라후 아크바르라고 말한다. 양손을 무릎 위에 단단히 놓고 손가락을 펼치며, 등은 곧게 지면과 평행하게 한다. 완전한 고요(투마으니나)로 이 자세를 유지한다. "위대하신 주님의 이름을 찬양하라"(꾸란 56:96)가 계시되었을 때 예언자 ﷺ께서 말씀하셨다: "이를 너희 루쿠의 지크르로 삼으라." 최소: 3회.`, ta: `கைகளை உயர்த்தி குனியும்போது அல்லாஹு அக்பர் என்று கூறுங்கள். இரு கைகளையும் முட்டுகளில் உறுதியாக வைத்து, விரல்களை விரித்து, முதுகை நேராக மற்றும் தரைக்கு இணையாக வைக்கவும். முழுமையான அமைதியுடன் (துமாஃநீனா) இதைப் பிடித்துக்கொள்ளுங்கள். "உமது மகத்தான இறைவனின் பெயரால் துதி செய்வீராக" (குர்ஆன் 56:96) அவதரித்தபோது நபி ﷺ கூறினார்: "இதை உங்கள் ருகூஃவின் திக்ர் ஆக்குங்கள்." குறைந்தபட்சம்: மூன்று முறை.`, si: `දෑත් ඔසවා නැමෙන විට අල්ලාහු අක්බර් කියන්න. දෑත් දෙකම දනහිස් මත දැඩිව තබා, ඇඟිලි පතුරුවා, කොන්ද කෙළින් සහ පොළොවට සමාන්තරව. සම්පූර්ණ සන්සුන්කමක් (තුමඃනීනා) සමඟ මෙය රඳවාගන්න. "ඔබේ ශ්‍රේෂ්ඨ සමිඳාගේ නාමයෙන් ස්තුති කරන්න" (කුර්ආන් 56:96) අවතීර්ණ වූ විට, නබි ﷺ පැවසූහ: "මෙය ඔබේ රුකූඃගේ දික්ර් ලෙස පත් කරන්න." අවම: වාර තුනකි.` },
  step6_translit:{ en: `Subhana Rabbiy al-'Azim` },
  step6_meaning: { en: `Glory be to my Lord, the Most Great.`, ms: `Maha Suci Tuhanku, Yang Maha Agung.`, tur: `Yüce Rabbim her türlü noksanlıktan münezzehtir.`, urd: `پاک ہے میرا رب، عظمت والا۔`, ben: `পবিত্র আমার রব, মহান।`, fas: `پاک و منزه است پروردگار من، آن بزرگ.`, zh: `讚頌我至尊之主清淨無瑕。`, yue: `讚頌我至尊之主清淨無瑕。`, ja: `わが至大なる主に栄光あれ。`, ru: `Слава Господу моему Великому.`, es: `Glorificado sea mi Señor, el Inmenso.`, ko: `위대하신 나의 주님께 영광이 있으소서.`, ta: `மிக மகத்தான என் இறைவன் தூயவன்.`, si: `මාගේ ශ්‍රේෂ්ඨ සමිඳාට ස්තුති වේවා.` },
  step6_xlabel:  { en: `Additional dhikr the Prophet ﷺ recited in ruku' (Muslim 771, Abu Dawud 872):` },
  step6_xtranslit:{ en: `Subhanakal-lahumma Rabbana wa bihamdika Allahummaghfir li. | Subbuhun Quddusun Rabbul-mala'ikati war-ruh. | Allahumma laka raka'tu wa bika amantu wa laka aslamtu, khasha'a laka sam'i wa basari wa mukhkhi wa 'azmi wa 'asabi.` },
  step6_xmeaning:{ en: `Glory be to You, O Allah our Lord, and praise be to You. O Allah, forgive me. | Most Glorified, Most Holy, Lord of the angels and the Spirit (Jibril). | O Allah, for You I have bowed, in You I believe, and to You I have submitted. My hearing, my sight, my mind, my bones, and my sinews are all humbled before You.` },

  step7_t: { en: `Rising from Ruku'`, ms: `Iktidal (Bangkit dari Rukuk)`, tur: `Rükûdan Doğrulma (İ'tidâl)`, urd: `قومہ (رکوع سے اٹھنا)`, ben: `রুকু থেকে উঠা (ইতিদাল)`, fas: `برخاستن از رکوع (اعتدال)`, zh: `自鞠躬起立（伊提達勒）`, yue: `自鞠躬起立（伊提達勒）`, ja: `ルクーから起き上がる（イゥティダール）`, ru: `Подъём с поясного поклона (Иътидаль)`, es: `Levantarse del Ruku' (I'tidal)`, ko: `루쿠에서 일어남 (이으티달)`, ta: `ருகூஃவிலிருந்து எழுதல் (இஃதிதால்)`, si: `රුකූඃ වෙතින් නැගිටීම (ඉඃතිදාල්)` },
  step7_d: { en: `Rise from bowing, raising the hands to the earlobes while saying Sami'allahu liman hamidah. Stand fully upright; this i'tidal position is a pillar of prayer and must be held with complete stillness before descending.`, ms: `Bangkit dari rukuk, sambil mengangkat tangan setentang cuping telinga, sebut Sami'allahu liman hamidah. Berdiri tegak sepenuhnya; kedudukan iktidal ini adalah rukun solat dan mesti dipegang dengan ketenangan sempurna sebelum turun.`, tur: `Rükûdan doğrul; elleri kulak yumuşaklarına kaldırırken Semiallahu limen hamideh de. Tam dik dur; bu i'tidâl konumu namazın rüknüdür ve eğilmeden önce tam bir sükûnetle tutulmalıdır.`, urd: `رکوع سے اٹھتے ہوئے، کانوں کی لو تک ہاتھ اٹھائیں اور سَمِعَ اللہُ لِمَنْ حَمِدَہ کہیں۔ پوری طرح سیدھے کھڑے ہوں؛ یہ اعتدال کا مقام نماز کا رکن ہے اور سجدے میں جانے سے پہلے مکمل سکون کے ساتھ رہنا چاہیے۔`, ben: `রুকু থেকে উঠার সময় কানের লতি পর্যন্ত হাত উঠান এবং সামি'আল্লাহু লিমান হামিদাহ বলুন। সম্পূর্ণ সোজা হয়ে দাঁড়ান; এই ইতিদাল অবস্থান নামাজের রুকন এবং সিজদায় যাওয়ার আগে পূর্ণ স্থিরতায় ধরে রাখতে হবে।`, fas: `از رکوع برخیز و در حالی که دست‌ها را تا نرمه گوش بلند می‌کنی، سَمِعَ اللهُ لِمَنْ حَمِدَه بگو. کاملاً راست بایست؛ این حالت اعتدال رکن نماز است و باید پیش از فرود به سجده با آرامش کامل نگه داشته شود.`, zh: `自鞠躬起立，將雙手舉至耳垂並誦『真主聽聞讚祂之人』。完全直身而立；此挺立之姿乃禮拜之主柱，下叩之前必須以完全之安寧守之。`, yue: `自鞠躬起立，將雙手舉至耳垂並誦『真主聽聞讚祂之人』。完全直身而立；此挺立之姿乃禮拜之主柱，下叩之前必須以完全之安寧守之。`, ja: `ルクーから起き上がり、両手を耳たぶの高さに挙げながら「サミアッラーフ・リマン・ハミダ」と唱える。完全に直立する。このイゥティダールの姿勢は礼拝の柱であり、平伏に下りる前に完全な静止で保たなければならない。`, ru: `Поднимись из поясного поклона, поднимая руки к мочкам ушей и говоря «Самиʿаллаху лиман хамидах». Встань полностью прямо; это положение иʿтидаль  –  столп намаза и должно удерживаться в полной неподвижности перед опусканием в земной поклон.`, es: `Levántate de la inclinación elevando las manos hasta los lóbulos de las orejas mientras dices Sami'allahu liman hamidah. Mantente completamente erguido; esta posición de i'tidal es un pilar de la oración y debe sostenerse con quietud completa antes de descender.`, ko: `루쿠에서 일어나며 손을 귀불 높이까지 들고 사미알라후 리만 하미다라고 말한다. 완전히 똑바로 선다; 이 이으티달 자세는 예배의 기둥이며, 부복으로 내려가기 전에 완전한 고요로 유지되어야 한다.`, ta: `ருகூஃவிலிருந்து எழுந்து, கைகளை காதின் மென்மையான பகுதி வரை உயர்த்தி, ஸமிஅல்லாஹு லிமன் ஹமிதா என கூறுங்கள். முழுமையாக நேராக நில்லுங்கள்; இந்த இஃதிதால் நிலை தொழுகையின் ருக்ன், மற்றும் கீழே சஜ்தாவுக்குச் செல்வதற்கு முன் முழுமையான அமைதியுடன் வைத்துக்கொள்ள வேண்டும்.`, si: `රුකූඃ වෙතින් නැගිට, දෑත් කන් උක්කු දක්වා ඔසවමින් සමිඃඅල්ලාහු ලිමන් හමිදා කියන්න. සම්පූර්ණයෙන් කෙළින් සිටින්න; මෙම ඉඃතිදාල් ඉරියව්ව සලාතයේ කුළුණයි, සජ්දාවට බැසීමට පෙර සම්පූර්ණ සන්සුන්කමින් රඳවාගත යුතුය.` },
  step7_translit:{ en: `Sami'allahu liman hamidah. Rabbana wa lakal-hamd, hamdan kathiran tayyiban mubarakan fih.` },
  step7_meaning: { en: `Allah hears whoever praises Him. Our Lord, all praise is Yours, abundant, pure and blessed praise.`, ms: `Allah mendengar sesiapa yang memuji-Nya. Wahai Tuhan kami, segala pujian bagi-Mu, pujian yang banyak, suci dan diberkati.`, tur: `Allah, kendisine hamd edeni işitir. Rabbimiz, hamd Sana'dır; bol, temiz ve mübarek bir hamd.`, urd: `اللہ نے سن لیا اس کی جس نے اس کی حمد کی۔ اے ہمارے رب، تیری ہی تعریف ہے، بہت زیادہ، پاکیزہ، با برکت۔`, ben: `আল্লাহ তাঁর প্রশংসাকারীর কথা শোনেন। হে আমাদের রব, তোমারই সমস্ত প্রশংসা, প্রচুর, পবিত্র ও বরকতময় প্রশংসা।`, fas: `خداوند می‌شنود هرکس را که او را ستایش کند. پروردگارا، ستایش از آنِ توست، ستایشی فراوان، پاک و مبارک.`, zh: `真主聽聞讚祂之人。我們的主啊，一切讚頌歸於祢，豐厚、純淨、蒙福之讚頌。`, yue: `真主聽聞讚祂之人。我們的主啊，一切讚頌歸於祢，豐厚、純淨、蒙福之讚頌。`, ja: `アッラーは彼を称える者を聞かれる。我らの主よ、称えはあなたに、豊かで清く祝福された称えなり。`, ru: `Услышал Аллах того, кто Его восхваляет. Господь наш, Тебе хвала  –  обильная, чистая, благословенная.`, es: `Allah escucha a quien Le alaba. Señor nuestro, Tuya es toda la alabanza, abundante, pura y bendita.`, ko: `알라께서는 그분을 찬양하는 자를 들으십니다. 우리의 주여, 모든 찬양은 당신께 있나이다, 풍성하고 순결하며 축복받은 찬양이.`, ta: `அல்லாஹ் தன்னைப் புகழ்பவரின் சொற்களைக் கேட்கிறான். எங்கள் இறைவனே, எல்லாப் புகழும் உனக்கே, ஏராளமான, தூய்மையான, ஆசீர்வதிக்கப்பட்ட புகழ்.`, si: `තමන්ව ස්තුති කරන තැනැත්තාගේ සිට අල්ලාහ් අසයි. අපගේ සමිඳාණෙනි, සියලු ස්තුති ඔබට ය, බහුල, පවිත්‍ර හා ආශීර්වාද ලත් ස්තුති.` },
  step7_xlabel:  { en: `Longer completion (Bukhari 799, the companion's addition that the Prophet approved):` },
  step7_xtranslit:{ en: `Mil'as-samawati wa mil'al-ard wa mil'a ma shi'ta min shay'in ba'd.` },
  step7_xmeaning:{ en: `Filling the heavens and the earth, and whatever You will beyond that.` },

  step8_t: { en: `First Prostration (Sujud)`, ms: `Sujud Pertama`, tur: `Birinci Secde (Sücud)`, urd: `پہلا سجدہ`, ben: `প্রথম সিজদা (সুজুদ)`, fas: `سجده اول`, zh: `第一次叩頭（蘇朱德）`, yue: `第一次叩頭（蘇朱德）`, ja: `最初の平伏（スジュード）`, ru: `Первый земной поклон (Суджуд)`, es: `Primera prostración (Sujud)`, ko: `첫 번째 부복 (수주드)`, ta: `முதல் சஜ்தா (ஸுஜூத்)`, si: `පළමු සජ්දාව (සුජූද්)` },
  step8_d: { en: `Descend to the ground with Allahu Akbar. Seven parts must touch the ground: the forehead including the nose, both palms, both knees, and the bottoms of both feet. The Prophet ﷺ said: "The nearest a servant is to his Lord is when he is in prostration, so make much supplication." (Muslim 482). When "Sabbih isma Rabbika al-A'la" (Qur'an 87:1) was revealed, the Prophet ﷺ said: "Make it your sujud dhikr." Minimum: three times.`, ms: `Turun ke tanah dengan Allahu Akbar. Tujuh anggota mesti menyentuh tanah: dahi termasuk hidung, kedua-dua tapak tangan, kedua-dua lutut, dan kedua-dua tapak kaki. Nabi ﷺ bersabda: "Saat paling hampir seorang hamba kepada Tuhannya ialah ketika sujud, maka perbanyakkanlah doa." (Muslim 482). Apabila "Sabbih isma Rabbika al-A'la" (Al-Quran 87:1) diturunkan, Nabi ﷺ bersabda: "Jadikanlah ia zikir sujudmu." Minimum: tiga kali.`, tur: `Allahu Ekber ile yere in. Yedi uzuv yere değmelidir: burun dahil alın, iki avuç, iki diz ve iki ayak tabanı. Peygamber ﷺ buyurdu: "Kulun Rabbine en yakın olduğu an secdededir, öyleyse çokça dua edin." (Müslim 482). "Sebbih isme Rabbike'l-A'lâ" (Kur'an 87:1) indiğinde Peygamber ﷺ buyurdu: "Onu secde zikriniz yapın." Asgari: üç kez.`, urd: `اللہ اکبر کے ساتھ زمین پر جائیں۔ سات اعضاء زمین کو لگنے چاہئیں: ناک سمیت پیشانی، دونوں ہتھیلیاں، دونوں گھٹنے، اور دونوں پاؤں کے تلوے۔ نبی ﷺ نے فرمایا: "بندہ اپنے رب سے سب سے زیادہ قریب اس وقت ہوتا ہے جب وہ سجدے میں ہوتا ہے، تو خوب دعا کرو۔" (مسلم ۴۸۲)۔ جب "سَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى" (قرآن ۸۷:۱) نازل ہوئی تو نبی ﷺ نے فرمایا: "اسے اپنے سجدے کا ذکر بنا لو۔" کم سے کم: تین مرتبہ۔`, ben: `আল্লাহু আকবার বলে মাটিতে নামুন। সাতটি অঙ্গ মাটি স্পর্শ করতে হবে: নাকসহ কপাল, উভয় হাতের তালু, উভয় হাঁটু, ও উভয় পায়ের তলা। নবী ﷺ বললেন: "বান্দা তার রবের সবচেয়ে নিকটবর্তী হয় সিজদায়, সুতরাং বেশি বেশি দোয়া কর।" (মুসলিম ৪৮২)। যখন "সাব্বিহিস্‌মা রাব্বিকাল আ'লা" (কুরআন ৮৭:১) অবতীর্ণ হলো, নবী ﷺ বললেন: "এটিকে তোমাদের সিজদার যিকর বানাও।" সর্বনিম্ন: তিনবার।`, fas: `با الله اکبر به زمین فرود آی. هفت عضو باید زمین را لمس کند: پیشانی همراه با بینی، دو کف دست، دو زانو و کف هر دو پا. پیامبر ﷺ فرمود: "نزدیک‌ترین لحظه بنده به پروردگارش هنگام سجده است، پس بسیار دعا کنید." (مسلم ۴۸۲). هنگامی که "سَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى" (قرآن ۸۷:۱) نازل شد، پیامبر ﷺ فرمود: "آن را ذکر سجده خود قرار دهید." حداقل: سه بار.`, zh: `誦『安拉胡阿克巴爾』下伏於地。七部位必須觸地：含鼻之額、雙掌、雙膝、雙腳掌。先知ﷺ言：「僕人最近其主之時乃叩頭時，故當多作祈求。」（穆斯林482）。當「你應當頌讚你至高之主之名」（古蘭87:1）降示時，先知ﷺ言：「以此作為汝叩頭之贊念。」至少：三次。`, yue: `誦『安拉胡阿克巴爾』下伏於地。七部位必須觸地：含鼻之額、雙掌、雙膝、雙腳掌。先知ﷺ言：「僕人最近其主之時乃叩頭時，故當多作祈求。」（穆斯林482）。當「你應當頌讚你至高之主之名」（古蘭87:1）降示時，先知ﷺ言：「以此作為汝叩頭之贊念。」至少：三次。`, ja: `アッラーフ・アクバルと唱えて地に降りる。7つの部位が地に触れねばならない：鼻を含む額、両手のひら、両膝、両足の裏。預言者ﷺは仰せられた：「僕がその主に最も近づくのは平伏の時である。それゆえ多く祈れ。」（ムスリム482）。「至高なる主の御名を称えよ」（クルアーン87:1）が啓示された際、預言者ﷺは仰せられた：「これをあなたがたのスジュードのズィクルとせよ。」最少：3回。`, ru: `Опустись на землю со словами Аллаху Акбар. Семь частей тела должны касаться земли: лоб вместе с носом, обе ладони, оба колена и подошвы обеих стоп. Пророк ﷺ сказал: «Ближе всего раб к своему Господу  –  когда он в земном поклоне, потому многократно взывайте.» (Муслим 482). Когда был ниспослан аят «Прославляй имя Господа твоего Всевышнего» (Коран 87:1), Пророк ﷺ сказал: «Сделайте это зикром вашего суджуда.» Минимум: три раза.`, es: `Desciende al suelo con Allahu Akbar. Siete partes deben tocar el suelo: la frente incluida la nariz, ambas palmas, ambas rodillas y las plantas de ambos pies. El Profeta ﷺ dijo: "Lo más cerca que está el siervo de su Señor es en la prostración, así que haced mucha súplica." (Muslim 482). Cuando se reveló "Glorifica el nombre de tu Señor el Altísimo" (Corán 87:1), el Profeta ﷺ dijo: "Hacedlo el dhikr de vuestro sujud." Mínimo: tres veces.`, ko: `알라후 아크바르라고 말하며 땅으로 내려간다. 일곱 부위가 땅에 닿아야 한다: 코를 포함한 이마, 양 손바닥, 양 무릎, 양발의 바닥. 예언자 ﷺ께서 말씀하셨다: "종이 주님께 가장 가까이 있는 때는 부복할 때이니, 두아를 많이 올리라." (무슬림 482). "지극히 높으신 주님의 이름을 찬양하라"(꾸란 87:1)가 계시되었을 때 예언자 ﷺ께서 말씀하셨다: "이를 너희 수주드의 지크르로 삼으라." 최소: 3회.`, ta: `அல்லாஹு அக்பர் என்று கூறி தரையில் இறங்குங்கள். ஏழு உறுப்புகள் தரையில் தொட வேண்டும்: மூக்கு உட்பட நெற்றி, இரண்டு உள்ளங்கைகள், இரண்டு முட்டுகள், மற்றும் இரண்டு பாதங்களின் அடிப்பாகம். நபி ﷺ கூறினார்: "அடியான் தனது இறைவனுக்கு மிக நெருக்கமாக இருப்பது சஜ்தாவிலேயே, எனவே அதிகமாக துஆ செய்யுங்கள்." (முஸ்லிம் 482). "மிக உயர்ந்த உமது இறைவனின் பெயரால் துதி செய்வீராக" (குர்ஆன் 87:1) அவதரித்தபோது நபி ﷺ கூறினார்: "இதை உங்கள் சஜ்தாவின் திக்ர் ஆக்குங்கள்." குறைந்தபட்சம்: மூன்று முறை.`, si: `අල්ලාහු අක්බර් කියමින් පොළොවට බසින්න. අවයව හතක් පොළොව ස්පර්ශ විය යුතුය: නහය ඇතුළත් නළල, දෑත් අත්ල දෙක, දනහිස් දෙක, සහ පාද දෙකේ පතුල්. නබි ﷺ පැවසූහ: "දාසයා තම සමිඳාට වඩාත්ම ළඟ වන්නේ සජ්දාවේ ය, එබැවින් බොහෝ සේ දුආ කරන්න." (මුස්ලිම් 482). "ඉතාම උසස් වූ ඔබේ සමිඳාගේ නාමයෙන් ස්තුති කරන්න" (කුර්ආන් 87:1) අවතීර්ණ වූ විට, නබි ﷺ පැවසූහ: "මෙය ඔබේ සුජූද්ගේ දික්ර් ලෙස පත් කරන්න." අවම: වාර තුනකි.` },
  step8_translit:{ en: `Subhana Rabbiy al-A'la` },
  step8_meaning: { en: `Glory be to my Lord, the Most High.`, ms: `Maha Suci Tuhanku, Yang Maha Tinggi.`, tur: `Yüce Rabbim her türlü noksanlıktan münezzehtir.`, urd: `پاک ہے میرا رب، بلند ترین۔`, ben: `পবিত্র আমার রব, সর্বোচ্চ।`, fas: `پاک و منزه است پروردگار من، آن بلندمرتبه.`, zh: `讚頌我至高之主清淨無瑕。`, yue: `讚頌我至高之主清淨無瑕。`, ja: `わが至高なる主に栄光あれ。`, ru: `Слава Господу моему Всевышнему.`, es: `Glorificado sea mi Señor, el Altísimo.`, ko: `지극히 높으신 나의 주님께 영광이 있으소서.`, ta: `மிக உயர்ந்த என் இறைவன் தூயவன்.`, si: `මාගේ අති උතුම් සමිඳාට ස්තුති වේවා.` },
  step8_xlabel:  { en: `Additional dhikr the Prophet ﷺ recited in sujud (Muslim 771, Muslim 486, Abu Dawud):` },
  step8_xtranslit:{ en: `Subhanakal-lahumma Rabbana wa bihamdika Allahummaghfir li. | Allahumma laka sajadtu wa bika amantu wa laka aslamtu, sajada wajhi lillathi khalaqahu wa sawwarahu wa shaqqa sam'ahu wa basarahu, tabarakallahu ahsanul-khaliqin. | Allahumma inni a'udhu biridaka min sakhatika wa bimu'afatika min 'uqubatika wa a'udhu bika minka la uhsi thana'an 'alayka anta kama athnayta 'ala nafsik.` },
  step8_xmeaning:{ en: `Glory be to You, O Allah our Lord, and praise be to You. O Allah, forgive me. | O Allah, for You I have prostrated, in You I believe, and to You I have submitted. My face has prostrated to the One who created it and shaped it and split open its hearing and sight; blessed is Allah, the best of creators. | O Allah, I seek refuge in Your pleasure from Your anger, in Your pardon from Your punishment. I seek refuge in You from You. I cannot enumerate Your praise; You are as You have praised Yourself.` },

  step9_t: { en: `Sitting Between the Two Prostrations`, ms: `Duduk Antara Dua Sujud`, tur: `İki Secde Arasında Oturuş`, urd: `دو سجدوں کے درمیان جلسہ`, ben: `দুই সিজদার মধ্যে বসা`, fas: `نشستن میان دو سجده`, zh: `兩次叩頭之間之坐`, yue: `兩次叩頭之間之坐`, ja: `二つの平伏の間の坐`, ru: `Сидение между двумя земными поклонами`, es: `Sentarse entre las dos prostraciones`, ko: `두 부복 사이의 앉음`, ta: `இரண்டு சஜ்தாக்களுக்கு இடையே அமர்தல்`, si: `සජ්දා දෙක අතර හිඳීම` },
  step9_d: { en: `Rise with Allahu Akbar and sit briefly between the two prostrations. This sitting is a pillar of prayer and must be still. Ibn Abbas (ra) narrated the full du'a the Prophet ﷺ said here: it covers seven comprehensive blessings every human needs:`, ms: `Bangkit dengan Allahu Akbar dan duduk sebentar antara dua sujud. Duduk ini adalah rukun solat dan mesti tenang. Ibn Abbas (ra) meriwayatkan doa penuh yang Nabi ﷺ baca di sini: ia merangkumi tujuh nikmat menyeluruh yang diperlukan setiap manusia:`, tur: `Allahu Ekber ile doğrul ve iki secde arasında kısa süre otur. Bu oturuş namazın rüknüdür ve sakin olmalıdır. İbn Abbâs (ra) Peygamber'in ﷺ burada okuduğu tam duayı rivayet etmiştir; her insanın muhtaç olduğu yedi kapsamlı bereketi kapsar:`, urd: `اللہ اکبر کے ساتھ اٹھ کر دو سجدوں کے درمیان مختصر بیٹھیں۔ یہ بیٹھنا نماز کا رکن ہے اور پر سکون ہونا چاہیے۔ ابن عباس (رض) نے یہاں نبی ﷺ کی پڑھی ہوئی مکمل دعا روایت کی ہے: یہ سات جامع نعمتوں کا احاطہ کرتی ہے جن کی ہر انسان کو ضرورت ہے:`, ben: `আল্লাহু আকবার বলে উঠে দুই সিজদার মধ্যে সংক্ষেপে বসুন। এই বসা নামাজের রুকন এবং স্থির হওয়া আবশ্যক। ইবন আব্বাস (রা) এখানে নবী ﷺ-এর পঠিত পূর্ণ দোয়া বর্ণনা করেছেন: এটি সাতটি ব্যাপক নিয়ামতকে আবৃত করে, যা প্রতিটি মানুষের প্রয়োজন:`, fas: `با الله اکبر برخیز و میان دو سجده اندکی بنشین. این نشستن رکن نماز است و باید آرام باشد. ابن عباس (رض) دعای کاملی را که پیامبر ﷺ در این موضع می‌خواند روایت کرده است: هفت نعمت جامع را که هر انسانی به آنها نیاز دارد دربر می‌گیرد:`, zh: `誦『安拉胡阿克巴爾』起身，於兩次叩頭之間短坐。此坐乃禮拜之主柱，必須安寧。伊本·阿巴斯（願主喜悅之）傳述先知ﷺ於此處所誦之完整祈禱詞：涵蓋每人皆需之七項全面恩典：`, yue: `誦『安拉胡阿克巴爾』起身，於兩次叩頭之間短坐。此坐乃禮拜之主柱，必須安寧。伊本·阿巴斯（願主喜悅之）傳述先知ﷺ於此處所誦之完整祈禱詞：涵蓋每人皆需之七項全面恩典：`, ja: `アッラーフ・アクバルと唱えて起き上がり、二つの平伏の間に短く座る。この座は礼拝の柱であり、静止していなければならない。イブン・アッバース（ラ）が、ここで預言者ﷺが唱えた完全な祈りを伝えている：すべての人間が必要とする七つの包括的な恵みを網羅している：`, ru: `Поднимись со словами Аллаху Акбар и кратко сядь между двумя земными поклонами. Это сидение  –  столп намаза и должно быть в неподвижности. Ибн Аббас (ра) передал полную дуа, которую Пророк ﷺ говорил здесь: она охватывает семь всеобъемлющих благ, в которых нуждается каждый человек:`, es: `Levántate con Allahu Akbar y siéntate brevemente entre las dos prostraciones. Este sentarse es un pilar de la oración y debe ser quieto. Ibn Abbas (ra) narró la du'a completa que el Profeta ﷺ decía aquí: abarca siete bendiciones integrales que todo ser humano necesita:`, ko: `알라후 아크바르라고 말하며 일어나 두 부복 사이에 잠시 앉는다. 이 앉음은 예배의 기둥이며 고요해야 한다. 이븐 압바스(라)께서 예언자 ﷺ께서 이 자리에서 외우셨던 완전한 두아를 전하셨다: 그것은 모든 인간이 필요로 하는 일곱 가지의 포괄적 축복을 담고 있다:`, ta: `அல்லாஹு அக்பர் என்று கூறி எழுந்து இரண்டு சஜ்தாக்களுக்கு இடையே சிறிது நேரம் அமருங்கள். இந்த அமர்தல் தொழுகையின் ருக்ன், மற்றும் அமைதியாக இருக்க வேண்டும். இப்னு அப்பாஸ் (ரலி) நபி ﷺ அவர்கள் இங்கு கூறிய முழு துஆவை அறிவித்தார்: இது ஒவ்வொரு மனிதனுக்கும் தேவையான ஏழு விரிவான அருட்களை உள்ளடக்கியது:`, si: `අල්ලාහු අක්බර් කියමින් නැගිට සජ්දා දෙක අතර කෙටි කලකට හිඳින්න. මෙම හිඳීම සලාතයේ කුළුණයි, සහ සන්සුන් විය යුතුය. ඉබ්න් අබ්බාස් (රළි) නබි ﷺ මෙහිදී කී සම්පූර්ණ දුආව වාර්තා කළේය: එය සෑම මනුෂ්‍යයෙකුටම අවශ්‍ය වන සමස්ත ආශීර්වාද හතක් ආවරණය කරයි:` },
  step9_translit:{ en: `Rabbighfir li, warhamni, wajburni, warfa'ni, warzuqni, wahdini, wa'afini, wa'fu 'anni.` },
  step9_meaning: { en: `My Lord, forgive me; have mercy on me; strengthen me (repair my affairs); raise me in rank; provide for me; guide me; grant me wellbeing; and pardon me.`, ms: `Ya Tuhanku, ampunilah aku; rahmatilah aku; perbaikilah keadaanku; angkatlah darjatku; berilah aku rezeki; tunjukilah aku; berilah aku kesejahteraan; dan maafkanlah aku.`, tur: `Rabbim! Beni bağışla; bana merhamet et; halimi düzelt; derecemi yükselt; bana rızık ver; beni doğru yola ilet; bana âfiyet ihsan eyle ve beni affet.`, urd: `اے میرے رب، مجھے بخش دے؛ مجھ پر رحم فرما؛ میری اصلاح فرما؛ میرا درجہ بلند کر؛ مجھے رزق دے؛ ہدایت دے؛ عافیت عطا فرما؛ اور مجھے معاف کر دے۔`, ben: `হে আমার রব, আমাকে ক্ষমা কর; আমার ওপর দয়া কর; আমাকে সংশোধন কর; আমার মর্যাদা বৃদ্ধি কর; আমাকে রিযিক দাও; হিদায়াত দাও; সুস্থতা দান কর; এবং আমাকে মাফ কর।`, fas: `پروردگارا، مرا بیامرز؛ بر من رحمت آور؛ کارهایم را اصلاح کن؛ منزلت مرا بالا ببر؛ روزی‌ام ده؛ هدایتم کن؛ تندرستی عطایم کن؛ و از من درگذر.`, zh: `我的主啊，赦宥我；憐憫我；使我堅固（修整我的事務）；提升我的品級；賜我給養；引導我；賜我安康；並寬恕我。`, yue: `我的主啊，赦宥我；憐憫我；使我堅固（修整我的事務）；提升我的品級；賜我給養；引導我；賜我安康；並寬恕我。`, ja: `わが主よ、私を赦したまえ；私に慈悲をたまえ；私を強くしたまえ（私のことを整えたまえ）；私の位を上げたまえ；私に糧をたまえ；私を導きたまえ；私に安寧を授けたまえ；そして私を許したまえ。`, ru: `Господь мой, прости меня; помилуй меня; укрепи меня (поправь мои дела); возвысь меня в положении; надели меня уделом; направь меня; даруй мне благополучие; и прости мне.`, es: `Señor mío, perdóname; ten misericordia de mí; corrige mis asuntos; elévame en rango; provéeme; guíame; concédeme bienestar; y exime mis faltas.`, ko: `오 나의 주여, 저를 용서하소서; 저에게 자비를 베푸소서; 저를 굳건히 하소서(저의 일을 바로잡아 주소서); 저를 격상시키소서; 저에게 양식을 주소서; 저를 인도하소서; 저에게 평안을 주소서; 그리고 저를 사하여 주소서.`, ta: `என் இறைவனே, என்னை மன்னிப்பாயாக; எனக்கு கருணை காட்டுவாயாக; என் காரியங்களை சரிசெய்வாயாக; என் தரத்தை உயர்த்துவாயாக; எனக்கு வாழ்வாதாரம் தருவாயாக; எனக்கு வழிகாட்டுவாயாக; எனக்கு நலன் தருவாயாக; மற்றும் என்னை சாந்திப்படுத்துவாயாக.`, si: `මාගේ සමිඳාණෙනි, මට සමාව දෙන්න; මට කරුණා කරන්න; මාව ශක්තිමත් කරන්න (මාගේ දේවල් සකස් කරන්න); මාගේ තනතුර ඉහළ දමන්න; මට පෝෂණය දෙන්න; මට මඟ පෙන්වන්න; මට යහපත දෙන්න; සහ මට සමාව දෙන්න.` },

  step10_t: { en: `Second Prostration`, ms: `Sujud Kedua`, tur: `İkinci Secde`, urd: `دوسرا سجدہ`, ben: `দ্বিতীয় সিজদা`, fas: `سجده دوم`, zh: `第二次叩頭`, yue: `第二次叩頭`, ja: `二度目の平伏`, ru: `Второй земной поклон`, es: `Segunda prostración`, ko: `두 번째 부복`, ta: `இரண்டாம் சஜ்தா`, si: `දෙවන සජ්දාව` },
  step10_d: { en: `Perform the second prostration exactly as the first with all the same dhikr. After this, rise for the next unit (in units one and three) with Allahu Akbar, or remain seated for Tashahhud (after the second and fourth units).`, ms: `Lakukan sujud kedua persis seperti yang pertama dengan zikir yang sama. Selepas ini, bangkit untuk rakaat seterusnya (pada rakaat satu dan tiga) dengan Allahu Akbar, atau kekal duduk untuk Tasyahud (selepas rakaat kedua dan keempat).`, tur: `İkinci secdeyi birinci ile aynı şekilde aynı zikirlerle yap. Sonra (1. ve 3. rekâtlarda) Allahu Ekber ile sonraki rekâta kalk; ya da (2. ve 4. rekâttan sonra) Teşehhüd için oturmaya devam et.`, urd: `دوسرا سجدہ بالکل پہلے کی طرح، انہی اذکار کے ساتھ ادا کریں۔ اس کے بعد، اگلی رکعت (پہلی اور تیسری) کے لیے اللہ اکبر کے ساتھ اٹھیں، یا تشہد کے لیے بیٹھے رہیں (دوسری اور چوتھی رکعت کے بعد)۔`, ben: `প্রথম সিজদার মতোই দ্বিতীয় সিজদা একই যিকর সহ আদায় করুন। এরপর পরবর্তী রাকাতের জন্য (এক ও তিন রাকাতে) আল্লাহু আকবার বলে উঠুন, অথবা তাশাহহুদের জন্য বসে থাকুন (দুই ও চার রাকাতের পর)।`, fas: `سجده دوم را دقیقاً مانند سجده اول و با همان اذکار به جای آور. پس از آن، با الله اکبر برای رکعت بعدی (در رکعت‌های اول و سوم) برخیز، یا برای تشهد بنشین (پس از رکعت‌های دوم و چهارم).`, zh: `以同樣之贊念，依首次叩頭同樣方式行第二次叩頭。然後（於第一、三拜）誦『安拉胡阿克巴爾』起身行下一拜，或留坐誦作證詞（於第二、四拜後）。`, yue: `以同樣之贊念，依首次叩頭同樣方式行第二次叩頭。然後（於第一、三拜）誦『安拉胡阿克巴爾』起身行下一拜，或留坐誦作證詞（於第二、四拜後）。`, ja: `二度目の平伏を最初と同じズィクルで全く同様に行う。その後、（1ラクア目と3ラクア目では）アッラーフ・アクバルと唱えて次のラクアのために起立し、または（2ラクア目と4ラクア目の後では）タシャッフドのために座ったままでいる。`, ru: `Соверши второй земной поклон точно так же, как первый, с теми же зикрами. После этого встань на следующий ракат (в первом и третьем ракатах) со словами Аллаху Акбар, или остайся сидеть для Ташаххуда (после второго и четвёртого ракатов).`, es: `Realiza la segunda prostración exactamente como la primera, con los mismos dhikr. Después, levántate para la siguiente rak'ah (en la primera y tercera) con Allahu Akbar, o permanece sentado para el Tashahhud (tras la segunda y cuarta).`, ko: `첫 번째 부복과 똑같이 같은 지크르로 두 번째 부복을 한다. 그 후, (1·3 라카에서는) 알라후 아크바르라고 말하며 다음 라카를 위해 일어나거나, (2·4 라카 뒤에서는) 타샤후드를 위해 앉은 채로 있는다.`, ta: `முதல் சஜ்தாவைப் போலவே, அதே திக்ர்களுடன், இரண்டாம் சஜ்தாவையும் செய்யுங்கள். இதன் பிறகு, (1ஆம் மற்றும் 3ஆம் ரக்அத்களில்) அடுத்த ரக்அத்துக்காக அல்லாஹு அக்பர் கூறி எழுங்கள், அல்லது (2ஆம் மற்றும் 4ஆம் ரக்அத்துகளுக்குப் பிறகு) தஷஹ்ஹுதுக்காக அமர்ந்திருங்கள்.`, si: `පළමු සජ්දාවට සමානම ආකාරයෙන් සහ එම දික්ර්වලින්ම දෙවන සජ්දාව ඉටු කරන්න. ඉන් පසු, (1 සහ 3 රකඅත්වලදී) ඊළඟ රකඅතට අල්ලාහු අක්බර් කියමින් නැගිට, හෝ (2 සහ 4 රකඅත්වලින් පසු) තෂහ්හුද් සඳහා හිඳ සිටින්න.` },
  step10_translit:{ en: `Subhana Rabbiy al-A'la` },
  step10_meaning: { en: `Glory be to my Lord, the Most High.`, ms: `Maha Suci Tuhanku, Yang Maha Tinggi.`, tur: `Yüce Rabbim her türlü noksanlıktan münezzehtir.`, urd: `پاک ہے میرا رب، بلند ترین۔`, ben: `পবিত্র আমার রব, সর্বোচ্চ।`, fas: `پاک و منزه است پروردگار من، آن بلندمرتبه.`, zh: `讚頌我至高之主清淨無瑕。`, yue: `讚頌我至高之主清淨無瑕。`, ja: `わが至高なる主に栄光あれ。`, ru: `Слава Господу моему Всевышнему.`, es: `Glorificado sea mi Señor, el Altísimo.`, ko: `지극히 높으신 나의 주님께 영광이 있으소서.`, ta: `மிக உயர்ந்த என் இறைவன் தூயவன்.`, si: `මාගේ අති උතුම් සමිඳාට ස්තුති වේවා.` },

  step11_t: { en: `Tashahhud  –  the Testimony of Faith in Prayer`, ms: `Tasyahud  –  Syahadat dalam Solat`, tur: `Teşehhüd  –  Namazda Şehâdet Sözü`, urd: `تشہد  –  نماز میں شہادت`, ben: `তাশাহহুদ  –  নামাজে শাহাদাত`, fas: `تشهد  –  گواهی ایمان در نماز`, zh: `作證詞（塔沙赫德）  –  禮拜中之信仰見證`, yue: `作證詞（塔沙赫德）  –  禮拜中之信仰見證`, ja: `タシャッフド  –  礼拝における信仰の証言`, ru: `Ташаххуд  –  свидетельство веры в намазе`, es: `Tashahhud  –  el testimonio de fe en la oración`, ko: `타샤후드  –  예배 안의 신앙 증언`, ta: `தஷஹ்ஹுத்  –  தொழுகையில் ஈமான் சாட்சியம்`, si: `තෂහ්හුද්  –  සලාතය තුළ ශ්‍රද්ධාවේ සාක්ෂිය` },
  step11_d: { en: `Recite the Tashahhud in the sitting after the second unit and in the final sitting. Point the right index finger toward the Qibla from the beginning of the Tashahhud until the end. When you reach the testimony (Ashhadu...), move the finger slightly. Ibn Mas'ud (ra) said the companions used to say various greetings in prayer until the Prophet ﷺ taught them this fixed wording.`, ms: `Baca Tasyahud dalam duduk selepas rakaat kedua dan dalam duduk terakhir. Tunjukkan jari telunjuk kanan ke arah Kiblat dari awal Tasyahud hingga akhir. Apabila sampai pada syahadat (Asyhadu...), gerakkan jari sedikit. Ibn Mas'ud (ra) berkata bahawa para Sahabat dahulunya membaca pelbagai salam dalam solat sehingga Nabi ﷺ mengajarkan mereka lafaz tetap ini.`, tur: `Teşehhüdü ikinci rekâttan sonraki oturuşta ve son oturuşta oku. Teşehhüdün başından sonuna dek sağ şehadet parmağıyla kıbleye işaret et. Şehadet bölümüne (Eşhedü...) gelince parmağı hafifçe oynat. İbn Mes'ûd (ra) sahabenin namazda çeşitli selamlar söylediğini, ta ki Peygamber ﷺ bu sabit metni öğretene kadar, rivayet eder.`, urd: `تشہد کو دوسری رکعت کے بعد بیٹھنے میں اور آخری بیٹھنے میں پڑھیں۔ تشہد کے آغاز سے آخر تک دائیں شہادت کی انگلی قبلہ کی طرف اشارہ کرتی رکھیں۔ جب گواہی (أَشْہَدُ...) تک پہنچیں تو انگلی کو ہلکی سی حرکت دیں۔ ابن مسعود (رض) نے بتایا کہ صحابہ نماز میں مختلف سلام کہتے تھے یہاں تک کہ نبی ﷺ نے انہیں یہ مقررہ الفاظ سکھائے۔`, ben: `দ্বিতীয় রাকাতের পরের বসায় ও শেষ বসায় তাশাহহুদ পড়ুন। তাশাহহুদের শুরু থেকে শেষ পর্যন্ত ডান হাতের তর্জনী কিবলার দিকে তাক করে রাখুন। যখন সাক্ষ্যে (আশহাদু...) পৌঁছাবেন, আঙুল সামান্য নাড়ান। ইবন মাসউদ (রা) বলেছেন, সাহাবিগণ নামাজে নানা রকম সালাম বলতেন যতক্ষণ না নবী ﷺ তাঁদের এই নির্দিষ্ট বাক্য শিখিয়ে দেন।`, fas: `تشهد را در نشستن پس از رکعت دوم و در نشستن پایانی بخوان. از آغاز تا پایان تشهد، انگشت سبابه راست را به سوی قبله بگیر. هنگامی که به شهادت (أَشْهَدُ...) رسیدی، انگشت را اندکی حرکت بده. ابن مسعود (رض) گفت که صحابه در نماز سلام‌های گوناگون می‌گفتند تا اینکه پیامبر ﷺ این متن ثابت را به آنان آموخت.`, zh: `於第二拜後之坐及末坐誦作證詞。自作證詞之始至終，右手食指指向基卜萊。讀至證言（『我作證……』）時，將指輕動。伊本·麥斯歐德（願主喜悅之）言：聖門弟子原於拜中誦各種致敬之辭，直至先知ﷺ教以此定文。`, yue: `於第二拜後之坐及末坐誦作證詞。自作證詞之始至終，右手食指指向基卜萊。讀至證言（『我作證……』）時，將指輕動。伊本·麥斯歐德（願主喜悅之）言：聖門弟子原於拜中誦各種致敬之辭，直至先知ﷺ教以此定文。`, ja: `タシャッフドは二ラクア目の後の坐と最終の坐で唱える。タシャッフドの始めから終わりまで、右手の人差し指をキブラの方向に指し示す。証言の箇所（アシュハドゥ……）に至ったとき、指を軽く動かす。イブン・マスウード（ラ）は、預言者ﷺがこの定型句を教えるまで、教友たちは礼拝中に様々な挨拶を唱えていたと伝えている。`, ru: `Прочти Ташаххуд в сидении после второго раката и в последнем сидении. С начала Ташаххуда до конца указывай правым указательным пальцем в сторону Киблы. Дойдя до свидетельства («Ашхаду…»), слегка пошевели пальцем. Ибн Масʿуд (ра) рассказал, что сподвижники говорили в молитве разные приветствия, пока Пророк ﷺ не научил их этому установленному тексту.`, es: `Recita el Tashahhud en el sentarse tras la segunda rak'ah y en el último sentarse. Apunta con el índice derecho hacia la Qibla desde el principio del Tashahhud hasta el final. Cuando llegues al testimonio (Ashhadu...), mueve ligeramente el dedo. Ibn Mas'ud (ra) refirió que los compañeros solían decir diversos saludos en la oración hasta que el Profeta ﷺ les enseñó esta fórmula fija.`, ko: `타샤후드를 두 번째 라카 뒤의 앉음과 마지막 앉음에서 낭송한다. 타샤후드의 처음부터 끝까지 오른쪽 검지를 끼블라 방향으로 가리킨다. 증언(아슈하두...) 부분에 이르면 손가락을 살짝 움직인다. 이븐 마스우드(라)께서는 동료들이 예배 중 다양한 인사말을 하다가 예언자 ﷺ께서 이 고정된 문구를 가르치셨다고 전하셨다.`, ta: `தஷஹ்ஹுதை இரண்டாம் ரக்அத்துக்குப் பின் அமர்தலிலும், கடைசி அமர்தலிலும் ஓதுங்கள். தஷஹ்ஹுதின் ஆரம்பத்திலிருந்து முடிவு வரை வலது ஆட்காட்டி விரலை கிப்லாவை நோக்கி நீட்டியிருங்கள். சாட்சியத்தை (அஷ்ஹது...) அடைந்தபோது விரலை சிறிது அசைக்கவும். இப்னு மஸ்ஊத் (ரலி) கூறினார்: சஹாபாக்கள் தொழுகையில் பல்வேறு சலாம்களைக் கூறிக் கொண்டிருந்தனர், நபி ﷺ அவர்களுக்கு இந்த நிலையான வாக்கியத்தை கற்றுக் கொடுக்கும் வரை.`, si: `තෂහ්හුද් දෙවන රකඅතයෙන් පසු හිඳීමේදී සහ අවසන් හිඳීමේදී කියවන්න. තෂහ්හුද්හි ආරම්භයේ සිට අවසානය දක්වා දකුණු සුළැඟිල්ල කිබ්ලාව දෙසට පෙන්වන්න. සාක්ෂියට (අශ්හදු…) පැමිණි විට ඇඟිල්ල මඳක් සෙලවන්න. ඉබ්න් මස්ඊද් (රළි) පැවසුවේ සහාබිවරුන් සලාතය තුළ විවිධ ආචාර කී බව, නබි ﷺ ඔවුන්ට මෙම ස්ථිර වදන් ඉගැන්වූ තෙක්.` },
  step11_translit:{ en: `At-tahiyyatu lillahi was-salawatu wat-tayyibat. As-salamu 'alayka ayyuhan-nabiyyu wa rahmatullahi wa barakatuh. As-salamu 'alayna wa 'ala 'ibadillahis-salihin. Ashhadu alla ilaha illallahu wa ashhadu anna Muhammadan 'abduhu wa rasuluh.` },
  step11_meaning: { en: `All verbal greetings, all prayers, and all pure words belong to Allah. Peace be upon you, O Prophet, and the mercy and blessings of Allah. Peace be upon us and upon all the righteous servants of Allah. I bear witness that there is no god but Allah, and I bear witness that Muhammad is His servant and messenger.` },

  step12_t: { en: `Salawat on the Prophet ﷺ (Al-Salat al-Ibrahimiyyah)`, ms: `Selawat ke atas Nabi ﷺ (Selawat Ibrahimiyyah)`, tur: `Peygamber'e ﷺ Salavat (Salât-ı İbrâhîmiyye)`, urd: `نبی ﷺ پر درود (الصلاۃ الإبراہیمیہ)`, ben: `নবী ﷺ-এর উপর দুরুদ (দুরুদে ইব্রাহিম)`, fas: `صلوات بر پیامبر ﷺ (صلوات ابراهیمیه)`, zh: `祝福先知ﷺ（易卜拉欣式祝福詞）`, yue: `祝福先知ﷺ（易卜拉欣式祝福詞）`, ja: `預言者ﷺへの祝福（サラート・イブラーヒーミーヤ）`, ru: `Салават Пророку ﷺ (Ас-Салят аль-Ибрахимиййя)`, es: `Salawat sobre el Profeta ﷺ (Al-Salat al-Ibrahimiyyah)`, ko: `예언자 ﷺ께 드리는 살라와트 (살라트 알이브라히미야)`, ta: `நபி ﷺ மீது ஸலவாத் (ஸலவாத் இப்ராஹீமிய்யா)`, si: `නබි ﷺ වෙත සලවාත් (සලාත් අල්-ඉබ්‍රාහීමිය්‍යා)` },
  step12_d: { en: `After the Tashahhud in the final sitting, recite the Ibrahimiyyah. When the companions asked the Prophet ﷺ how to send blessings upon him, he taught them this exact wording: it links his name with Ibrahim (as), the patriarch of monotheism. It is called Ibrahimiyyah because it uses Ibrahim as a benchmark of accepted blessings:`, ms: `Selepas Tasyahud dalam duduk terakhir, baca Selawat Ibrahimiyyah. Apabila para Sahabat bertanya Nabi ﷺ bagaimana hendak berselawat kepadanya, baginda mengajarkan lafaz yang tepat ini: ia menghubungkan nama baginda dengan Ibrahim (as), bapa tauhid. Dinamakan Ibrahimiyyah kerana ia menggunakan Ibrahim sebagai tanda aras selawat yang diterima:`, tur: `Son oturuştaki Teşehhüdden sonra Salât-ı İbrâhîmiyye'yi oku. Sahabe Peygamber'e ﷺ ona nasıl salavat getirileceğini sorduğunda, kendisine bu tam metni öğretti: adını tevhidin atası İbrahim (as) ile ilişkilendirir. Kabul edilen salavatın ölçütü olarak İbrahim'i kullandığı için İbrâhîmiyye denir:`, urd: `آخری بیٹھنے میں تشہد کے بعد، صلوۃ ابراہیمیہ پڑھیں۔ جب صحابہ نے نبی ﷺ سے پوچھا کہ آپ پر کیسے درود بھیجا جائے تو آپ نے انہیں یہ مخصوص الفاظ سکھائے: یہ آپ کے نام کو ابراہیم (ع) سے جوڑتا ہے، جو توحید کے باپ ہیں۔ اسے ابراہیمیہ کہا جاتا ہے کیونکہ یہ ابراہیم کو مقبول صلوۃ کے معیار کے طور پر استعمال کرتا ہے:`, ben: `শেষ বসায় তাশাহহুদের পর দুরুদে ইব্রাহিম পাঠ করুন। সাহাবিগণ যখন নবী ﷺ-কে জিজ্ঞেস করলেন কীভাবে তাঁর উপর দুরুদ পাঠাবেন, তিনি এই সুনির্দিষ্ট শব্দাবলী তাঁদের শেখালেন: এটি তাঁর নামকে তাওহিদের পিতা ইব্রাহিম (আ)-এর সাথে সংযুক্ত করে। ইব্রাহিমিয়া বলা হয় কারণ এটি ইব্রাহিমকে গৃহীত দুরুদের মাপকাঠি হিসেবে ব্যবহার করে:`, fas: `پس از تشهد در نشستن پایانی، صلوات ابراهیمیه را بخوان. هنگامی که صحابه از پیامبر ﷺ پرسیدند چگونه بر او درود بفرستند، این متن دقیق را به آنان آموخت: نام او را با ابراهیم (ع)، پدر توحید، پیوند می‌دهد. ابراهیمیه نامیده می‌شود زیرا ابراهیم را معیار درود پذیرفته‌شده قرار می‌دهد:`, zh: `於末坐之作證詞後，誦易卜拉欣式祝福詞。聖門弟子問先知ﷺ如何向其致祝福時，先知教其此確切文辭：將其名與認主獨一之祖易卜拉欣（願主賜其平安）相連。稱為易卜拉欣式者，因以易卜拉欣為被接受之祝福之基準：`, yue: `於末坐之作證詞後，誦易卜拉欣式祝福詞。聖門弟子問先知ﷺ如何向其致祝福時，先知教其此確切文辭：將其名與認主獨一之祖易卜拉欣（願主賜其平安）相連。稱為易卜拉欣式者，因以易卜拉欣為被接受之祝福之基準：`, ja: `最終の坐におけるタシャッフドの後、サラート・イブラーヒーミーヤを唱える。教友たちが預言者ﷺに彼への祝福をどう送るか尋ねたとき、彼はこの正確な文言を教えられた：彼の名を唯一神信仰の祖イブラーヒーム（に平安あれ）と結びつける。受け入れられる祝福の基準としてイブラーヒームを用いるため、イブラーヒーミーヤと呼ばれる：`, ru: `После Ташаххуда в последнем сидении прочти Ас-Салят аль-Ибрахимиййя. Когда сподвижники спросили Пророка ﷺ, как посылать на него салават, он научил их этому точному тексту: он связывает его имя с Ибрахимом (мир ему), праотцом единобожия. Называется Ибрахимиййя, потому что использует Ибрахима как эталон принятого салавата:`, es: `Tras el Tashahhud en el último sentarse, recita el Salat Ibrahimiyyah. Cuando los compañeros preguntaron al Profeta ﷺ cómo enviarle bendiciones, les enseñó esta fórmula exacta: vincula su nombre con Ibrahim (as), el patriarca del monoteísmo. Se llama Ibrahimiyyah porque toma a Ibrahim como referencia de las bendiciones aceptadas:`, ko: `마지막 앉음에서 타샤후드 후에 살라트 알이브라히미야를 낭송한다. 동료들이 예언자 ﷺ께 그분께 어떻게 축복을 보내야 하는지 여쭈었을 때, 그분께서는 이 정확한 문구를 가르치셨다: 그분의 이름을 유일신 신앙의 조상 이브라힘(평화가 그에게)과 연결한다. 이브라힘을 받아들여진 축복의 기준으로 삼기에 이브라히미야라 불린다:`, ta: `கடைசி அமர்தலில் தஷஹ்ஹுதுக்குப் பின் ஸலவாத் இப்ராஹீமிய்யாவை ஓதுங்கள். சஹாபாக்கள் நபி ﷺ அவர்களிடம் அவர் மீது எவ்வாறு ஸலவாத் அனுப்புவது என கேட்டபோது, அவர் இந்த துல்லியமான வாக்கியங்களை அவர்களுக்கு கற்றுக் கொடுத்தார்: இது அவரது பெயரை தௌஹீதின் தந்தையான இப்ராஹீம் (அலை) உடன் இணைக்கிறது. ஏற்கப்பட்ட ஸலவாத்துக்கு இப்ராஹீமை ஒரு அளவுகோலாக பயன்படுத்துவதால் இது இப்ராஹீமிய்யா எனப்படுகிறது:`, si: `අවසන් හිඳීමේදී තෂහ්හුද්වලින් පසු, සලාත් අල්-ඉබ්‍රාහීමිය්‍යා කියවන්න. සහාබිවරුන් නබි ﷺ ගෙන් උන් වෙත සලවාත් කෙසේ එවිය යුතුදැයි ඇසූ විට, ඔහු මෙම නිශ්චිත වදන් ඔවුන්ට ඉගැන්වීය: එය උන් වහන්සේගේ නාමය තව්හීදයේ පියා වූ ඉබ්‍රාහීම් (අලෛ) සමඟ සම්බන්ධ කරයි. පිළිගත් සලවාත්හි ප්‍රමිතිය ලෙස ඉබ්‍රාහීම් යොදන බැවින් එය ඉබ්‍රාහීමිය්‍යා නම් වේ:` },
  step12_translit:{ en: `Allahumma salli 'ala Muhammadin wa 'ala ali Muhammad, kama sallayta 'ala Ibrahima wa 'ala ali Ibrahim, innaka Hamidun Majid. Allahumma barik 'ala Muhammadin wa 'ala ali Muhammad, kama barakta 'ala Ibrahima wa 'ala ali Ibrahim, innaka Hamidun Majid.` },
  step12_meaning: { en: `O Allah, send Your mercy upon Muhammad and upon the family of Muhammad, as You sent Your mercy upon Ibrahim and upon the family of Ibrahim; You are Praiseworthy, Glorious. O Allah, send Your blessings upon Muhammad and upon the family of Muhammad, as You sent Your blessings upon Ibrahim and upon the family of Ibrahim; You are Praiseworthy, Glorious.` },

  step13_t: { en: `Final Du'a Before Taslim: Seeking Refuge from Four Things`, ms: `Doa Akhir Sebelum Salam: Memohon Perlindungan dari Empat Perkara`, tur: `Selâmdan Önce Son Dua: Dört Şeyden Sığınma`, urd: `سلام سے پہلے آخری دعا: چار چیزوں سے پناہ`, ben: `সালামের পূর্বে শেষ দোয়া: চারটি বিষয় থেকে আশ্রয় প্রার্থনা`, fas: `دعای پایانی پیش از سلام: پناه‌جویی از چهار چیز`, zh: `撒蘭前最後祈禱詞：求四事之庇`, yue: `撒蘭前最後祈禱詞：求四事之庇`, ja: `タスリームの前の最後の祈り：四つのものからの庇護を求める`, ru: `Последняя дуа перед таслимом: прибежище от четырёх вещей`, es: `Du'a final antes del taslim: refugio de cuatro cosas`, ko: `타슬림 전의 마지막 두아: 네 가지로부터의 피난 구함`, ta: `தஸ்லீமுக்கு முன் இறுதி துஆ: நான்கு பொருள்களிலிருந்து பாதுகாப்பு கேட்டல்`, si: `තස්ලීම් වලට පෙර අවසන් දුආව: දේ හතරකින් රැකවරණය පැතීම` },
  step13_d: { en: `Before ending the prayer, the Prophet ﷺ commanded Muslims to seek refuge from four things. He said: "When one of you completes the Tashahhud, let him seek refuge with Allah from four things." (Bukhari, Muslim). After this, you may make any personal du'a you wish; the final sitting is one of the best moments for supplication:`, ms: `Sebelum mengakhiri solat, Nabi ﷺ memerintahkan umat Islam memohon perlindungan daripada empat perkara. Baginda bersabda: "Apabila salah seorang kamu menyempurnakan Tasyahud, hendaklah dia memohon perlindungan kepada Allah daripada empat perkara." (Bukhari, Muslim). Selepas ini, kamu boleh membuat sebarang doa peribadi yang dikehendaki; duduk terakhir adalah antara saat terbaik untuk berdoa:`, tur: `Namazı bitirmeden önce Peygamber ﷺ Müslümanlara dört şeyden Allah'a sığınmayı emretti. Buyurdu: "Sizden biriniz Teşehhüdü bitirdiğinde dört şeyden Allah'a sığınsın." (Buhârî, Müslim). Bundan sonra dilediğin kişisel duayı yapabilirsin; son oturuş duanın kabul olunduğu en faziletli vakitlerden biridir:`, urd: `نماز ختم کرنے سے پہلے، نبی ﷺ نے مسلمانوں کو چار چیزوں سے پناہ مانگنے کا حکم دیا۔ آپ نے فرمایا: "جب تم میں سے کوئی تشہد پورا کر لے، تو وہ چار چیزوں سے اللہ کی پناہ مانگے۔" (بخاری، مسلم)۔ اس کے بعد، آپ جو بھی ذاتی دعا کرنا چاہیں کر سکتے ہیں؛ آخری بیٹھنا دعا کے بہترین لمحات میں سے ہے:`, ben: `নামাজ শেষ করার আগে নবী ﷺ মুসলমানদেরকে চারটি বিষয় থেকে আশ্রয় চাইতে আদেশ দিলেন। তিনি বললেন: "তোমাদের কেউ তাশাহহুদ সম্পন্ন করলে, সে যেন চারটি বিষয় থেকে আল্লাহর কাছে আশ্রয় চায়।" (বুখারি, মুসলিম)। এরপর আপনি যে কোনো ব্যক্তিগত দোয়া করতে পারেন; শেষ বসা দোয়ার শ্রেষ্ঠ মুহূর্তগুলোর একটি:`, fas: `پیش از پایان نماز، پیامبر ﷺ به مسلمانان فرمان داد از چهار چیز پناه بجویند. فرمود: "هرگاه یکی از شما تشهد را به پایان رساند، از چهار چیز به خدا پناه ببرد." (بخاری، مسلم). پس از آن، می‌توانی هر دعای شخصی که می‌خواهی بکنی؛ نشستن پایانی از بهترین لحظات دعاست:`, zh: `禮拜完結之前，先知ﷺ命令穆斯林求四事之庇護。其言：「汝等之一誦畢作證詞後，當求真主庇護四事。」（布哈里、穆斯林）。此後，可作任何個人祈禱；末坐乃祈禱之最佳時刻之一：`, yue: `禮拜完結之前，先知ﷺ命令穆斯林求四事之庇護。其言：「汝等之一誦畢作證詞後，當求真主庇護四事。」（布哈里、穆斯林）。此後，可作任何個人祈禱；末坐乃祈禱之最佳時刻之一：`, ja: `礼拝を終える前に、預言者ﷺはムスリムに四つのものからの庇護を求めるよう命じられた。彼は仰せられた：「あなたがたの一人がタシャッフドを終えたら、四つのものからアッラーに庇護を求めなさい。」（ブハーリー、ムスリム）。この後、望むどのような個人的な祈りも捧げてよい。最終の坐は祈願に最も適した時の一つである：`, ru: `Перед окончанием намаза Пророк ﷺ повелел мусульманам искать прибежища от четырёх вещей. Он сказал: «Когда один из вас закончит Ташаххуд, пусть прибегнет к Аллаху от четырёх.» (Бухари, Муслим). После этого ты можешь сделать любую личную дуа; последнее сидение  –  одно из лучших мгновений для мольбы:`, es: `Antes de terminar la oración, el Profeta ﷺ ordenó a los musulmanes buscar refugio de cuatro cosas. Dijo: "Cuando uno de vosotros complete el Tashahhud, que se refugie en Allah de cuatro cosas." (Bujari, Muslim). Después puedes hacer cualquier du'a personal que desees; el último sentarse es uno de los mejores momentos para la súplica:`, ko: `예배를 마치기 전에, 예언자 ﷺ께서 무슬림들에게 네 가지로부터 피난을 구하라고 명하셨다. 그분께서 말씀하셨다: "너희 중 누구든 타샤후드를 마치면, 네 가지에 대해 알라께 피난을 구하라." (부카리, 무슬림). 이 후에는 원하는 어떤 개인적 두아라도 드릴 수 있다; 마지막 앉음은 두아에 가장 좋은 순간 중 하나이다:`, ta: `தொழுகையை முடிக்கும் முன், நபி ﷺ முஸ்லிம்களுக்கு நான்கு பொருள்களிலிருந்து பாதுகாப்பு கேட்க கட்டளையிட்டார். அவர் கூறினார்: "உங்களில் ஒருவர் தஷஹ்ஹுதை முடித்தால், அவர் நான்கு பொருள்களிலிருந்து அல்லாஹ்விடம் பாதுகாப்பு கேட்கட்டும்." (புகாரி, முஸ்லிம்). இதன் பிறகு, நீங்கள் விரும்பும் எந்த தனிப்பட்ட துஆவையும் செய்யலாம்; கடைசி அமர்தல் துஆவின் சிறந்த தருணங்களில் ஒன்று:`, si: `සලාතය අවසන් කිරීමට පෙර, නබි ﷺ මුස්ලිම්වරුන්ට දේ හතරකින් රැකවරණය පැතීමට අණ කළහ. ඔහු පැවසූහ: "ඔබෙන් කෙනෙකු තෂහ්හුද් අවසන් කළ විට, දේ හතරකින් අල්ලාහ්ගේ රැකවරණය පතන්න." (බුහාරි, මුස්ලිම්). ඉන් පසු, ඔබට අවශ්‍ය ඕනෑම පුද්ගලික දුආවක් කළ හැකිය; අවසන් හිඳීම දුආ සඳහා හොඳම මොහොත් වලින් එකකි:` },
  step13_translit:{ en: `Allahumma inni a'udhu bika min 'adhabil-qabr, wa min 'adhabi-nar, wa min fitnati mahya wal-mamat, wa min sharri fitnatil-masihid-dajjal.` },
  step13_meaning: { en: `O Allah, I seek refuge in You from the punishment of the grave, from the punishment of the Fire, from the trials of life and death, and from the evil of the trial of the False Messiah (al-Dajjal).` },

  step14_t: { en: `The Closing Salutation (Taslim)`, ms: `Salam Penutup (Taslim)`, tur: `Selâm (Taslîm)`, urd: `سلام (تسلیم)`, ben: `সমাপ্তির সালাম (তাসলিম)`, fas: `سلام پایانی (تسلیم)`, zh: `結禮致詞（撒蘭）`, yue: `結禮致詞（撒蘭）`, ja: `終わりの挨拶（タスリーム）`, ru: `Заключительное приветствие (Таслим)`, es: `Saludo final (Taslim)`, ko: `마지막 인사 (타슬림)`, ta: `முடிவின் சலாம் (தஸ்லீம்)`, si: `අවසන් සලාම (තස්ලීම්)` },
  step14_d: { en: `Turn the head to the right and say the salutation, then to the left and repeat it. This formally concludes the prayer. You have stood before Allah, bowed to Him, and prostrated to Him.`, ms: `Palingkan kepala ke kanan dan sebut salam, kemudian ke kiri dan ulangi. Ini secara rasmi menamatkan solat. Kamu telah berdiri di hadapan Allah, rukuk kepada-Nya, dan sujud kepada-Nya.`, tur: `Başı sağa çevirip selam ver, sonra sola çevirip aynısını yap. Bu, namazı resmen sona erdirir. Allah'ın huzurunda durdun, O'na eğildin ve O'na secde ettin.`, urd: `سر کو دائیں طرف موڑ کر سلام کہیں، پھر بائیں طرف موڑ کر دہرائیں۔ یہ نماز کو باضابطہ طور پر ختم کر دیتا ہے۔ آپ اللہ کے سامنے کھڑے ہوئے، اس کے سامنے رکوع کیا، اور اس کے سامنے سجدہ کیا۔`, ben: `মাথা ডান দিকে ফিরিয়ে সালাম বলুন, এরপর বাম দিকে ফিরিয়ে পুনরাবৃত্তি করুন। এটি আনুষ্ঠানিকভাবে নামাজ সমাপ্ত করে। আপনি আল্লাহর সামনে দাঁড়িয়েছেন, তাঁর সামনে রুকু করেছেন, ও তাঁর সামনে সিজদা করেছেন।`, fas: `سر را به سمت راست بگردان و سلام بده، سپس به سمت چپ و آن را تکرار کن. این رسماً نماز را پایان می‌دهد. در پیشگاه خدا ایستادی، در برابر او رکوع و در برابر او سجده کردی.`, zh: `將頭轉向右側並致撒蘭，繼而轉向左側重複之。此正式結束禮拜。汝已立於真主之前、向祂鞠躬、向祂叩頭。`, yue: `將頭轉向右側並致撒蘭，繼而轉向左側重複之。此正式結束禮拜。汝已立於真主之前、向祂鞠躬、向祂叩頭。`, ja: `頭を右に向けて挨拶を唱え、次に左に向けて繰り返す。これで礼拝が正式に終了する。あなたはアッラーの御前に立ち、御前に屈み、御前に平伏した。`, ru: `Поверни голову вправо и произнеси приветствие, затем влево и повтори его. Это формально завершает намаз. Ты предстоял пред Аллахом, кланялся Ему и совершал земной поклон пред Ним.`, es: `Gira la cabeza a la derecha y di el saludo, luego a la izquierda y repítelo. Esto concluye formalmente la oración. Te has puesto de pie ante Allah, te has inclinado ante Él y te has prostrado ante Él.`, ko: `머리를 오른쪽으로 돌려 인사말을 하고, 다시 왼쪽으로 돌려 반복한다. 이로써 예배가 공식적으로 끝난다. 그대는 알라 앞에 섰고, 그분께 굽혔으며, 그분께 부복하였다.`, ta: `தலையை வலதுபக்கம் திருப்பி சலாம் கூறுங்கள், பின் இடதுபக்கம் திருப்பி அதை மீண்டும் கூறுங்கள். இது தொழுகையை முறையாக நிறைவு செய்கிறது. நீங்கள் அல்லாஹ்வுக்கு முன் நின்றீர்கள், அவனுக்குக் குனிந்தீர்கள், அவனுக்கு சஜ்தா செய்தீர்கள்.`, si: `හිස දකුණට හරවා සලාම් කියන්න, පසුව වමට හරවා එය නැවත කියන්න. මෙයින් සලාතය විධිමත් ලෙස අවසන් වේ. ඔබ අල්ලාහ් ඉදිරියේ සිට, ඔහු වෙත රුකූඃ කර, ඔහු වෙත සජ්දා කළෙහිය.` },
  step14_translit:{ en: `As-salamu 'alaykum wa rahmatullah` },
  step14_meaning: { en: `Peace be upon you and the mercy of Allah.`, ms: `Sejahteralah ke atasmu dan rahmat Allah.`, tur: `Allah'ın selâmı ve rahmeti üzerinize olsun.`, urd: `تم پر سلامتی اور اللہ کی رحمت ہو۔`, ben: `তোমাদের ওপর শান্তি ও আল্লাহর রহমত বর্ষিত হোক।`, fas: `سلام و رحمت خداوند بر شما باد.`, zh: `願平安與真主之慈憫降於你們。`, yue: `願平安與真主之慈憫降於你哋。`, ja: `あなたがたの上に平安とアッラーの慈悲があるように。`, ru: `Мир вам и милость Аллаха.`, es: `Que la paz y la misericordia de Allah sean sobre vosotros.`, ko: `너희에게 평안과 알라의 자비가 함께하기를.`, ta: `உங்கள் மீது சாந்தியும் அல்லாஹ்வின் கருணையும் உண்டாகட்டும்.`, si: `ඔබට සාමය සහ අල්ලාහ්ගේ කරුණාව උදා වේවා.` },

  /* ── After-prayer adhkar ────────────────────────────────── */
  after_h: { en: `Adhkar After Prayer`, ms: `Zikir Selepas Solat`, tur: `Namazdan Sonraki Zikirler`, urd: `نماز کے بعد اذکار`, ben: `নামাজের পরের আযকার`, fas: `اذکار پس از نماز`, zh: `禮拜後之贊念詞`, yue: `禮拜後之贊念詞`, ja: `礼拝後のズィクル`, ru: `Зикры после намаза`, es: `Adhkar después de la oración`, ko: `예배 후의 지크르`, ta: `தொழுகைக்குப் பிறகு ஜிக்ர்`, si: `සලාතයෙන් පසු දික්ර්` },
  after_intro: { en: `The Prophet ﷺ remained seated after every fard prayer to recite these. They are short, profound, and authentically transmitted.`, ms: `Nabi ﷺ tetap duduk selepas setiap solat fardu untuk membaca ini. Ia ringkas, mendalam dan diriwayatkan dengan sahih.`, tur: `Peygamber ﷺ her farz namazdan sonra bunları okumak için oturmaya devam ederdi. Kısa, derin ve sahih senetle nakledilmişlerdir.`, urd: `نبی ﷺ ہر فرض نماز کے بعد یہ اذکار پڑھنے کے لیے بیٹھے رہتے۔ یہ مختصر، گہرے اور صحیح سند سے منقول ہیں۔`, ben: `নবী ﷺ প্রত্যেক ফরজ নামাজের পর এগুলো পাঠ করতে বসে থাকতেন। এগুলো সংক্ষিপ্ত, গভীর অর্থবহ এবং বিশুদ্ধ সনদে বর্ণিত।`, fas: `پیامبر ﷺ پس از هر نماز فرض برای خواندن این اذکار نشسته می‌ماند. این اذکار کوتاه، ژرف و با سند صحیح روایت شده‌اند.`, zh: `先知ﷺ於每次主命拜功後皆繼續端坐以誦念此等贊詞。它們言簡意深，傳承確鑿。`, yue: `先知ﷺ於每次主命拜功後皆繼續端坐以誦念此等贊詞。佢哋言簡意深，傳承確鑿。`, ja: `預言者ﷺは毎回のファルド礼拝の後、これらを唱えるために座り続けられた。短く、深く、確実な伝承で伝えられている。`, ru: `Пророк ﷺ оставался сидеть после каждого фарда, чтобы прочесть эти зикры. Они кратки, глубоки и переданы по достоверной цепочке.`, es: `El Profeta ﷺ permanecía sentado después de cada oración fard para recitar estos. Son breves, profundos y transmitidos con autenticidad.`, ko: `예언자 ﷺ께서는 매 파르드 예배 후 이를 낭송하기 위해 앉아 계셨습니다. 짧고 깊으며 진정한 전승으로 전해졌습니다.`, ta: `நபி ﷺ ஒவ்வொரு ஃபர்ள் தொழுகைக்குப் பிறகும் இவற்றை ஓத அமர்ந்திருந்தார். இவை சுருக்கமானவை, ஆழமானவை, மற்றும் சரியான ஸனத் மூலம் அறிவிக்கப்பட்டவை.`, si: `නබි ﷺ සෑම ෆර්ද් සලාතයකින් පසුම මේවා කියවීමට හිඳ සිටියහ. මේවා කෙටි, ගැඹුරු, සහ විශ්වසනීය පරම්පරාවකින් සම්ප්‍රේෂණය වී ඇත.` },

  after1_t: { en: `Seeking Forgiveness, then Greeting the Lord of Peace`, ms: `Memohon Keampunan, kemudian Memuji Tuhan yang Maha Sejahtera`, tur: `İstiğfar, ardından Selâm'ın Sahibine Selâm`, urd: `استغفار، پھر سلامتی کے رب کو سلام`, ben: `ক্ষমা প্রার্থনা, এরপর শান্তির অধিপতির প্রশংসা`, fas: `طلب آمرزش، سپس درود بر پروردگار سلام`, zh: `求恕，繼之向平安之主致頌`, yue: `求恕，繼之向平安之主致頌`, ja: `赦しを請い、平安の主への挨拶`, ru: `Просьба о прощении, затем приветствие Господа Мира`, es: `Pedir perdón, luego saludar al Señor de la Paz`, ko: `용서를 구한 후, 평화의 주님께 인사`, ta: `மன்னிப்பு கோரல், பின் சாந்தியின் இறைவனை வாழ்த்துதல்`, si: `සමාව ඉල්ලීම, පසුව සමාදානයේ සමිඳාට ආචාර කිරීම` },
  after1_src: { en: `Muslim 591`, ms: `Muslim 591`, tur: `Müslim 591`, urd: `مسلم ۵۹۱`, ben: `মুসলিম ৫৯১`, fas: `مسلم ۵۹۱`, zh: `穆斯林591`, yue: `穆斯林591`, ja: `ムスリム591`, ru: `Муслим 591`, es: `Muslim 591`, ko: `무슬림 591`, ta: `முஸ்லிம் 591`, si: `මුස්ලිම් 591` },
  after1_translit:{ en: `Astaghfirullah (×3). Allahumma antas-salam wa minkas-salam, tabarakta dhal-jalali wal-ikram.` },
  after1_meaning: { en: `I seek Allah's forgiveness (three times). O Allah, You are Peace and from You comes peace. Blessed are You, Possessor of Glory and Honour.` },
  after1_note:    { en: `The Prophet ﷺ said this immediately after giving the taslim, then turned to face his companions. We begin by asking forgiveness because even in our prayer we may have fallen short in our focus and presence.` },

  after2_t: { en: `Tahlil: Declaring the Oneness of Allah`, ms: `Tahlil: Mengisytiharkan Keesaan Allah`, tur: `Tehlîl: Allah'ın Birliğini İlân`, urd: `تہلیل: اللہ کی وحدانیت کا اعلان`, ben: `তাহলিল: আল্লাহর একত্ব ঘোষণা`, fas: `تهلیل: اعلان یگانگی خداوند`, zh: `念清真詞（塔赫利勒）：宣告真主獨一`, yue: `念清真詞（塔赫利勒）：宣告真主獨一`, ja: `タフリール：アッラーの唯一性の宣言`, ru: `Тахлиль: провозглашение Единства Аллаха`, es: `Tahlil: declarar la Unicidad de Allah`, ko: `타흘릴: 알라의 유일성 선언`, ta: `தஹ்லீல்: அல்லாஹ்வின் ஒருமையை அறிவித்தல்`, si: `තහ්ලීල්: අල්ලාහ්ගේ ඒකත්වය ප්‍රකාශ කිරීම` },
  after2_src: { en: `Muslim 592`, ms: `Muslim 592`, tur: `Müslim 592`, urd: `مسلم ۵۹۲`, ben: `মুসলিম ৫৯২`, fas: `مسلم ۵۹۲`, zh: `穆斯林592`, yue: `穆斯林592`, ja: `ムスリム592`, ru: `Муслим 592`, es: `Muslim 592`, ko: `무슬림 592`, ta: `முஸ்லிம் 592`, si: `මුස්ලිම් 592` },
  after2_translit:{ en: `La ilaha illallahu wahdahu la sharika lah, lahul-mulku wa lahul-hamd, wa huwa 'ala kulli shay'in qadir.` },
  after2_meaning: { en: `There is no god but Allah alone, He has no partner. His is the dominion and His is all praise, and He has power over all things.` },

  after3_t: { en: `Ayat al-Kursi: The Verse of the Throne`, ms: `Ayat al-Kursi: Ayat Singgahsana`, tur: `Âyetü'l-Kürsî: Kürsî Âyeti`, urd: `آیۃ الکرسی: کرسی والی آیت`, ben: `আয়াতুল কুরসি: কুরসির আয়াত`, fas: `آیة الکرسی: آیه کرسی`, zh: `寶座章節（庫爾西經文）`, yue: `寶座章節（庫爾西經文）`, ja: `玉座の節（アーヤトゥル＝クルスィー）`, ru: `Аят аль-Курси: Аят Престола`, es: `Ayat al-Kursi: el Versículo del Trono`, ko: `아야툴 쿠르시: 보좌의 절`, ta: `ஆயத்துல் குர்ஸி: அரியணை வசனம்`, si: `ආයතුල් කුර්සී: සිංහාසන පදය` },
  after3_src: { en: `Al-Nasa'i 9928 (authenticated by al-Albani)`, ms: `Al-Nasa'i 9928 (disahihkan oleh al-Albani)`, tur: `Nesâî 9928 (Elbânî sahih sayar)`, urd: `النسائی ۹۹۲۸ (البانی نے صحیح قرار دیا)`, ben: `আন-নাসায়ি ৯৯২৮ (আল-আলবানি কর্তৃক সহিহ)`, fas: `نسائی ۹۹۲۸ (آلبانی صحیح دانسته)`, zh: `奈薩儀9928（艾爾巴尼判為正傳）`, yue: `奈薩儀9928（艾爾巴尼判為正傳）`, ja: `ナサーイー9928（アルバーニーが正統と判定）`, ru: `ан-Насаи 9928 (хадис достоверный по аль-Альбани)`, es: `Al-Nasa'i 9928 (autenticado por al-Albani)`, ko: `안나사이 9928 (알알바니가 진본으로 판정)`, ta: `அந்-நஸாஈ 9928 (அல்-அல்பானி சரியெனப் பதிவு)`, si: `අන්-නසාඊ 9928 (අල්-අල්බානී විසින් සහීහ් ලෙස පිළිගත්)` },
  after3_translit:{ en: `Allahu la ilaha illa huwal-hayyul-qayyum, la ta'khudhuhu sinatun wa la nawm, lahu ma fis-samawati wa ma fil-ard, man dhal-ladhi yashfa'u 'indahu illa bi-idhnih, ya'lamu ma bayna aydihim wa ma khalfahum, wa la yuhituna bishay'im-min 'ilmihi illa bima sha', wasi'a kursiyyuhus-samawati wal-ard, wa la ya'uduhu hifzuhuma wa huwal-'aliyyul-'azim.` },
  after3_meaning: { en: `Allah, there is no deity except Him, the Ever-Living, the Sustainer of existence. Neither drowsiness overtakes Him nor sleep. To Him belongs whatever is in the heavens and whatever is on the earth. Who could intercede with Him except by His permission? He knows what is before them and what will be after them, and they encompass not a thing of His knowledge except for what He wills. His Throne extends over the heavens and the earth, and their preservation does not tire Him. He is the Most High, the Most Great.` },
  after3_note:    { en: `Qur'an 2:255. The Prophet ﷺ said: "Whoever recites Ayat al-Kursi after every obligatory prayer, nothing stands between him and his entering Paradise except death." (Abu Umamah (ra); authenticated by al-Albani.) It is the greatest verse in the Qur'an.` },

  after4_t: { en: `Tasbih, Tahmid, Takbir: 99 Counts Completed with Tahlil`, ms: `Tasbih, Tahmid, Takbir: 99 Bilangan Disempurnakan dengan Tahlil`, tur: `Tesbih, Tahmid, Tekbir: 99 Sayım, Tehlîl ile Tamamlanır`, urd: `تسبیح، تحمید، تکبیر: ۹۹ کا شمار تہلیل سے مکمل`, ben: `তাসবিহ, তাহমিদ, তাকবির: ৯৯ গণনা তাহলিল দিয়ে পূর্ণ`, fas: `تسبیح، تحمید، تکبیر: ۹۹ شمارش با تهلیل تکمیل می‌شود`, zh: `贊主清淨、贊主、贊主大：九十九次以清真詞圓滿`, yue: `贊主清淨、贊主、贊主大：九十九次以清真詞圓滿`, ja: `タスビーフ、タハミード、タクビール：99回を超えてタフリールで完結`, ru: `Тасбих, Тахмид, Такбир: 99 счётов, завершаемых тахлилем`, es: `Tasbih, Tahmid, Takbir: 99 conteos completados con el Tahlil`, ko: `타스비흐, 타흐미드, 타크비르: 99회를 타흘릴로 완성`, ta: `தஸ்பீஹ், தஹ்மீத், தக்பீர்: 99 எண்ணிக்கை தஹ்லீலுடன் முழுமை`, si: `තස්බීහ්, තහ්මීද්, තක්බීර්: 99 ගණන් තහ්ලීල් සමඟ සම්පූර්ණ` },
  after4_src: { en: `Muslim 597`, ms: `Muslim 597`, tur: `Müslim 597`, urd: `مسلم ۵۹۷`, ben: `মুসলিম ৫৯৭`, fas: `مسلم ۵۹۷`, zh: `穆斯林597`, yue: `穆斯林597`, ja: `ムスリム597`, ru: `Муслим 597`, es: `Muslim 597`, ko: `무슬림 597`, ta: `முஸ்லிம் 597`, si: `මුස්ලිම් 597` },
  after4_translit:{ en: `Subhanallah (×33). Alhamdulillah (×33). Allahu Akbar (×33). La ilaha illallahu wahdahu la sharika lah, lahul-mulku wa lahul-hamd, wa huwa 'ala kulli shay'in qadir.` },
  after4_meaning: { en: `Glory be to Allah (33 times). All praise is to Allah (33 times). Allah is the Greatest (33 times). [Then:] There is no god but Allah alone, He has no partner; His is the dominion and all praise belongs to Him, and He has power over all things.` },
  after4_note:    { en: `The Prophet ﷺ said: "Whoever says this after every prayer, his sins are forgiven even if they were as abundant as the foam of the sea." (Muslim). The story behind the 33+33+33: Fatimah (ra) came to the Prophet ﷺ asking for a servant because her hands were sore from grinding. He said: "Shall I not tell you what is better than what you asked for? When you go to bed, say Subhanallah 33 times, Alhamdulillah 33 times, and Allahu Akbar 34 times; that is better for you than a servant."` },

  after5_t: { en: `After Fajr and Maghrib: Additional 10 Times`, ms: `Selepas Subuh dan Maghrib: Tambahan 10 Kali`, tur: `Sabah ve Akşamdan Sonra: Ek 10 Kez`, urd: `فجر اور مغرب کے بعد: مزید ۱۰ مرتبہ`, ben: `ফজর ও মাগরিবের পর: অতিরিক্ত ১০ বার`, fas: `پس از فجر و مغرب: ۱۰ بار افزوده`, zh: `晨禮與昏禮後：另加十次`, yue: `晨禮與昏禮後：另加十次`, ja: `ファジュルとマグリブの後：さらに10回`, ru: `После Фаджра и Магриба: дополнительно 10 раз`, es: `Después del Fajr y el Maghrib: 10 veces adicionales`, ko: `파즈르와 마그립 후: 추가 10회`, ta: `ஃபஜ்ர் மற்றும் மக்ரிபுக்குப் பிறகு: கூடுதலாக 10 முறை`, si: `ෆජ්ර් සහ මග්රිබ්වලින් පසු: අමතර වාර 10ක්` },
  after5_src: { en: `Tirmidhi 3474 (sahih)`, ms: `Tirmidhi 3474 (sahih)`, tur: `Tirmizî 3474 (sahih)`, urd: `ترمذی ۳۴۷۴ (صحیح)`, ben: `তিরমিযি ৩৪৭৪ (সহিহ)`, fas: `ترمذی ۳۴۷۴ (صحیح)`, zh: `提爾米茲3474（正傳）`, yue: `提爾米茲3474（正傳）`, ja: `ティルミズィー3474（サヒーフ）`, ru: `Тирмизи 3474 (сахих)`, es: `Tirmidhi 3474 (sahih)`, ko: `티르미디 3474 (사히)`, ta: `திர்மிதி 3474 (சஹீஹ்)`, si: `තිර්මිදී 3474 (සහීහ්)` },
  after5_translit:{ en: `La ilaha illallahu wahdahu la sharika lah, lahul-mulku wa lahul-hamd, yuhyi wa yumit, wa huwa 'ala kulli shay'in qadir.` },
  after5_meaning: { en: `There is no god but Allah alone, He has no partner; His is the dominion and all praise belongs to Him. He gives life and causes death, and He has power over all things.` },
  after5_note:    { en: `Recite 10 times after Fajr and 10 times after Maghrib. The Prophet ﷺ said: "Whoever says this ten times after Fajr and Maghrib: ten good deeds are written for him, ten sins are erased, he is raised ten ranks, is protected from every evil throughout his day and night, and no one comes on the Day of Resurrection with better deeds except one who said more."` },

  transliteration_label: { en: `Transliteration`, ms: `Transliterasi`, tur: `Okunuş`, urd: `نقل حرفی`, ben: `উচ্চারণ`, fas: `آوانگاری`, zh: `音譯`, yue: `音譯`, ja: `音訳`, ru: `Транслитерация`, es: `Transliteración`, ko: `음역`, ta: `ஒலிபெயர்ப்பு`, si: `උච්චාරණය` },
  meaning_label: { en: `Meaning`, ms: `Maksud`, tur: `Anlam`, urd: `معنی`, ben: `অর্থ`, fas: `معنا`, zh: `意義`, yue: `意義`, ja: `意味`, ru: `Значение`, es: `Significado`, ko: `의미`, ta: `பொருள்`, si: `අරුත` },

} satisfies Record<string, PartialLangMap>;
